function erklaerung(d){
  if(d.clean_score==null) return "Noch nicht bewertet – es fehlen die Zutaten-/Produktdaten.";
  const zus=num(d.p_zusatzstoffe), nova=num(d.p_nova), zut=num(d.p_zutaten);
  const plus=[], minus=[];
  if(zus>=15) plus.push("keine Zusatzstoffe"); else if(zus!=null && zus<=4) minus.push("künstliche Süßstoffe/Zusätze");
  if(nova>=15) plus.push("unverarbeitet (Vollwert)"); else if(nova!=null && nova<=3) minus.push("stark verarbeitet"); else if(nova!=null) minus.push("verarbeitet/isoliert");
  if(zut!=null && zut>=27) plus.push("hochwertige Zutaten"); else if(zut!=null && zut<=15) minus.push("isolierte/raffinierte Zutaten");
  let t="";
  if(plus.length) t+="Stark: "+plus.join(", ")+". ";
  if(minus.length) t+="Schwächer: "+minus.join(", ")+". ";
  return t.trim();
}
/* Supabase/PostgREST deckelt jede Abfrage HART bei 1000 Zeilen – .range() hebt das nicht auf.
   Bei 1.062 aktiven Produkten waren dadurch 62 Produkte in der App unsichtbar.
   Deshalb: seitenweise laden, bis der Server weniger als eine volle Seite liefert.
   🔴 STABILE SORTIERUNG PFLICHT (19.07.2026): Ohne .order() liefert PostgREST die
   Seiten in unstabiler Reihenfolge – ab >1000 Produkten überlappen sie, Zeilen fallen
   durch (gemessen: 1606 Zeilen roh, aber nur 1373 verschieden → 233 Produkte unsichtbar).
   .order("id") trennt die Seiten sauber. Jede seitenweise Abfrage MUSS sortieren. */
async function fetchAlleProdukte(){
  const SEITE=1000; let alle=[], von=0;
  for(let i=0;i<20;i++){
    const {data,error}=await client.from("v_web_produkte").select("*").order("id").range(von, von+SEITE-1);
    if(error) throw error;
    if(!data || !data.length) break;
    alle=alle.concat(data);
    if(data.length<SEITE) break;
    von+=SEITE;
  }
  return alle;
}
let ALL=[]; let STK={}; let SUPP_BIL={}; let WISSEN=[];
function stkOf(pid){ const g=pid?num(STK[pid]):null; return (g&&g>0)?g:null; }
const client = supabase.createClient(SUPABASE_URL, SUPABASE_KEY, {
  auth: { persistSession:true, autoRefreshToken:true, detectSessionInUrl:true, storage: window.localStorage, storageKey:"sb-cleanbase-auth" }
});

/* ---- Auth (Magic-Link) + Premium ---- */
let ME = null; // {benutzer_id, name, is_premium, is_admin, tier}
let MY_FEATURES = null; // Set der freigeschalteten feature_keys (per Stufe)
/* Der Testschalter stand frueher auf HARTKODIERTEN Stufen (base/move/elite) - Stufen,
   die es in der Datenbank gar nicht mehr gibt. Er zeigte also eine Welt, die niemand
   je zu sehen bekam. Jetzt kommen die Mengen aus derselben Matrix wie im Adminbereich:
   was du hier siehst, ist, was der Nutzer sieht. */
let _TIER_SETS = null;   // {gast:Set, free:Set, premium:Set} - nur fuer Admins geladen
async function ladeTierSets(){
  if(!(ME&&ME.is_admin)) { _TIER_SETS=null; return; }
  try{
    const {data}=await client.rpc("cb_features_matrix");
    const s={};
    (data||[]).forEach(r=>{ (s[r.tier]=s[r.tier]||new Set()); if(r.enabled) s[r.tier].add(r.feature_key); });
    _TIER_SETS=s;
  }catch(e){ _TIER_SETS=null; }
}
function hasFeat(k){
  // Admin-Testschalter „Ansehen als"
  if(window._tierOverride && ME && ME.is_admin && _TIER_SETS){
    const s=_TIER_SETS[window._tierOverride];
    return s ? s.has(k) : false;
  }
  if(MY_FEATURES) return MY_FEATURES.has(k);
  return !!(ME&&ME.is_premium);   /* Notfall: RPC nicht erreichbar */
}
function setTierOverride(t){
  window._tierOverride = t || null;
  const c=document.getElementById("tierOvChip"); if(c) c.querySelectorAll('button').forEach(b=>b.style.fontWeight=(b.dataset.t===(t||''))?'800':'400');
  try{ if(typeof render==='function') render(); }catch(e){}
  try{ const v=document.getElementById('rezeptView'); if(v&&v.style.display!=='none'&&typeof loadRezepte==='function') loadRezepte(); }catch(e){}
}
/* „Ansehen als“ ist ein ENTWICKLER-Werkzeug, kein Admin-Werkzeug.
   Wer Produkte pflegt (Admin), braucht keinen Modus-Umschalter im Bild – der
   verwirrt dort nur. Deshalb hängt der Balken an ME.entwickler, nicht an is_admin. */
function mountTierOvChip(){
  const ex=document.getElementById("tierOvChip");
  /* Im Admin-Backend (Produkt-Pflege) hat der Consumer-Vorschau-Schalter „Ansehen als"
     nichts verloren – dort verdeckt er nur das Arbeitsblatt. Auf der Consumer-App bleibt er. */
  if(window.__ADMIN_PAGE){ if(ex) ex.remove(); return; }
  if(!(ME&&ME.entwickler)){ if(ex) ex.remove(); return; }
  if(ex) return;
  ladeTierSets();
  const c=document.createElement("div"); c.id="tierOvChip";
  c.style.cssText="position:fixed;bottom:82px;right:10px;z-index:70;background:var(--k-111827);color:var(--k-ffffff);border-radius:999px;padding:5px 8px;font-size:11px;display:flex;gap:3px;align-items:center;box-shadow:0 4px 14px rgba(0,0,0,.3)";
  c.innerHTML='<span style="opacity:.7;margin:0 3px">Ansehen als:</span>'
    +[['','ich'],['gast','Gast'],['free','Free'],['premium','Premium']].map(t=>
      '<button data-t="'+t[0]+'" onclick="setTierOverride(\''+t[0]+'\')" style="background:none;border:0;color:var(--k-ffffff);cursor:pointer;font-size:11px;padding:3px 7px;border-radius:8px">'+t[1]+'</button>').join("");
  document.body.appendChild(c);
  setTierOverride(window._tierOverride||'');
}
/* Auch der GAST hat jetzt Rechte - vorher hatte er keine, und weil die Produktkarte
   gar nicht fragte, sah er alles. "Was nicht abgefragt wird, ist erlaubt."
   Die Stufe "gast" ist im Adminbereich einstellbar wie free und premium. */
async function refreshMyFeatures(){
  try{
    const rpc = ME ? "cb_my_features" : "cb_gast_features";
    const {data}=await client.rpc(rpc);
    MY_FEATURES=new Set((data||[]).map(x=>x.feature_key));
  }catch(e){ MY_FEATURES=null; }
}
async function _startCheckout(plan, consent){
  try{
    // Zustimmung (Zeitstempel + Text) best-effort persistieren; Fehler nicht blockierend
    if(consent){ try{ await client.rpc("cb_consent_speichern",{p_consent: consent}); }catch(_){} }
    const {data,error}=await client.functions.invoke('stripe-checkout',{ body:{ plan: plan||'month', consent: consent||null } });
    if(error||!data||!data.url) throw new Error((data&&data.error)||'no url');
    window.location.href=data.url;
  }catch(e){
    alert("Premium wird gerade eingerichtet – bitte in Kürze erneut versuchen.");
  }
}
