/* ---- Zyklus (EN-12) ---- */
function pfZyklusToggle(){
  const box=document.getElementById("pfZyklusBox"); if(!box) return;
  const g=(document.getElementById("pfGeschlecht")||{}).value||"";
  box.style.display = (g==="weiblich") ? "" : "none";
}
async function loadZyklus(){
  pfZyklusToggle();
  try{
    const {data}=await client.rpc("cb_zyklus_get");
    const r=(data&&data[0])||{};
    window._zyklus = (r.start) ? {start:r.start, laenge:r.laenge||28, ende:r.ende||null} : {};
    _selVal("pfZykStart", r.start||"");
    _selVal("pfZykEnde", r.ende||"");
    _selVal("pfZykLen", r.laenge||28);
    var sv=document.getElementById("pfZykStkVal"); if(sv) sv.value=r.blutung||"";
    var wv=document.getElementById("pfZykWohlVal"); if(wv) wv.value=(r.wohl!=null?String(r.wohl):"");
    zykCalInit();
    zykUpdateLabels();
  }catch(e){ window._zyklus={}; }
}
async function saveZyklus(){
  const msg=document.getElementById("pfZykMsg");
  const s=(document.getElementById("pfZykStart")||{}).value||null;
  const e=(document.getElementById("pfZykEnde")||{}).value||null;
  const l=parseInt((document.getElementById("pfZykLen")||{}).value,10)||28;
  const stk=(document.getElementById("pfZykStkVal")||{}).value||null;
  const wohl=parseInt((document.getElementById("pfZykWohlVal")||{}).value,10)||null;
  if(!s){ if(msg){ msg.style.color="var(--k-dc2626)"; msg.textContent="Bitte im Kalender einen Zyklusbeginn antippen."; } return; }
  if(e && e<s){ if(msg){ msg.style.color="var(--k-dc2626)"; msg.textContent="Periodenende darf nicht vor dem Beginn liegen."; } return; }
  const {error}=await client.rpc("cb_zyklus_speichern",{p_start:s,p_laenge:l,p_ende:e,p_blutung:stk,p_wohl:wohl});
  if(error){ if(msg){ msg.style.color="var(--k-dc2626)"; msg.textContent="Fehler: "+error.message; } return; }
  window._zyklus={start:s, laenge:Math.min(45,Math.max(20,l)), ende:e};
  if(msg){ msg.style.color="var(--k-16a34a)"; msg.textContent="✓ gespeichert – Hinweise erscheinen im Tagebuch."; }
  zyklusPhaseText();
  if(document.getElementById("tbZyklus")) renderZyklusHint();
}
/* Zyklus-Kalender als Bereichswähler: 1. Klick = Start, 2. Klick = Ende */
function zykCalInit(){
  var box=document.getElementById('pfZykCal'); if(!box) return;
  var s=(document.getElementById('pfZykStart')||{}).value||'';
  var e=(document.getElementById('pfZykEnde')||{}).value||'';
  var base=s?new Date(s+'T00:00:00'):new Date();
  window._zykCal={y:base.getFullYear(), m:base.getMonth(), start:s||null, end:e||null, phase:(s&&!e)?'end':'start'};
  zykCalRender();
}
function zykUpdateLabels(){
  var s=(document.getElementById('pfZykStart')||{}).value||'';
  var e=(document.getElementById('pfZykEnde')||{}).value||'';
  var fmt=function(ds){ if(!ds) return '–'; return new Date(ds+'T00:00:00').toLocaleDateString('de-DE',{day:'2-digit',month:'2-digit',year:'numeric'}); };
  var sl=document.getElementById('pfZykStartLbl'); if(sl) sl.textContent=fmt(s);
  var el=document.getElementById('pfZykEndeLbl'); if(el) el.textContent=fmt(e);
  var dl=document.getElementById('pfZykDauerLbl');
  if(dl){ if(s&&e){ var dd=Math.round((new Date(e+'T00:00:00')-new Date(s+'T00:00:00'))/86400000)+1; dl.textContent=(dd>=1?dd+' Tag'+(dd===1?'':'e'):'–'); } else { dl.textContent='–'; } }
  window._zyklus=window._zyklus||{}; if(s){ window._zyklus.start=s; window._zyklus.ende=e||null; if(!window._zyklus.laenge) window._zyklus.laenge=28; }
  zyklusPhaseText();
}
function zykCalNav(n){ var st=window._zykCal; if(!st) return; st.m+=n; if(st.m<0){st.m=11;st.y--;} if(st.m>11){st.m=0;st.y++;} zykCalRender(); }
function zykCalPick(ds){
  var st=window._zykCal; if(!st) return;
  if(st.phase==='start' || (st.start&&st.end)){ st.start=ds; st.end=null; st.phase='end'; }
  else { if(ds<st.start){ st.start=ds; st.phase='end'; } else { st.end=ds; st.phase='start'; } }
  var si=document.getElementById('pfZykStart'); if(si) si.value=st.start||'';
  var ei=document.getElementById('pfZykEnde'); if(ei) ei.value=st.end||'';
  zykCalRender();
  if(typeof zykUpdateLabels==='function') zykUpdateLabels();
}
function zykCalRender(){
  var box=document.getElementById('pfZykCal'); if(!box) return;
  var st=window._zykCal; if(!st) return;
  var first=new Date(st.y, st.m, 1);
  var startWd=(first.getDay()+6)%7;
  var daysInM=new Date(st.y, st.m+1, 0).getDate();
  var mName=first.toLocaleDateString('de-DE',{month:'long',year:'numeric'});
  var wd=['M','D','M','D','F','S','S'], today=tbToday();
  var html='<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px">'
    +'<button type="button" onclick="zykCalNav(-1)" style="border:0;background:none;cursor:pointer;font-size:16px;padding:2px 8px">‹</button>'
    +'<span style="font-weight:700;font-size:13.5px">'+mName+'</span>'
    +'<button type="button" onclick="zykCalNav(1)" style="border:0;background:none;cursor:pointer;font-size:16px;padding:2px 8px">›</button></div>';
  html+='<div style="display:grid;grid-template-columns:repeat(7,1fr);gap:2px;text-align:center;font-size:10px;color:var(--muted);margin-bottom:2px">'+wd.map(function(w){return '<div>'+w+'</div>';}).join('')+'</div>';
  html+='<div style="display:grid;grid-template-columns:repeat(7,1fr);gap:2px">';
  var i; for(i=0;i<startWd;i++) html+='<div></div>';
  var d; for(d=1; d<=daysInM; d++){
    var ds=st.y+'-'+String(st.m+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');
    var isStart=st.start===ds, isEnd=st.end===ds;
    var inRange=st.start&&st.end&&ds>st.start&&ds<st.end;
    var future=ds>today;
    var bg=(isStart||isEnd)?'var(--k-db2777)':(inRange?'var(--k-fbcfe8)':'transparent');
    var col=(isStart||isEnd)?'var(--k-ffffff)':(future?'var(--k-c9c4bd)':'var(--ink)');
    html+='<button type="button" '+(future?'disabled':'onclick="zykCalPick(\''+ds+'\')"')+' style="aspect-ratio:1;border:0;border-radius:8px;background:'+bg+';color:'+col+';cursor:'+(future?'default':'pointer')+';font-size:12.5px">'+d+'</button>';
  }
  html+='</div>';
  var hint = (st.phase==='end') ? 'Jetzt <b>Periodenende</b> wählen (oder denselben Tag).' : 'Nächster Klick = <b>Zyklusbeginn</b>, dann das <b>Ende</b>.';
  html+='<div style="font-size:11px;color:var(--muted);margin-top:6px">'+hint+' Danach <b>Speichern</b>.</div>';
  box.innerHTML=html;
}
// Zyklustag & Phase; nutzt tbToday() als Bezugstag
function zyklusInfo(){
  const z=window._zyklus; if(!z||!z.start) return null;
  const start=new Date(z.start+"T00:00:00");
  const ref=(typeof tbToday==="function")? new Date(tbToday()+"T00:00:00") : new Date();
  const diff=Math.floor((ref-start)/86400000);
  if(isNaN(diff)||diff<0) return null;
  const len=z.laenge||28;
  const day=(diff%len)+1;
  const zyklen=Math.floor(diff/len);
  const nextStart=new Date(start.getTime()+(zyklen+1)*len*86400000);
  const bis=Math.round((nextStart-ref)/86400000);
  let mensDays=5;
  if(z.ende){ var _ed=Math.floor((new Date(z.ende+"T00:00:00")-start)/86400000)+1; if(!isNaN(_ed)&&_ed>=1) mensDays=Math.min(14,_ed); }
  let phase="Follikelphase", hint=null;
  if(day<=mensDays){
    phase="Menstruation";
    hint={emoji:"🩸", title:"Menstruation · Tag "+day+" von "+mensDays,
      text:"Durch den Blutverlust ist der <b>Eisenbedarf</b> oft erhöht. Eisenreiche Lebensmittel (Hülsenfrüchte, Haferflocken, grünes Gemüse, rotes Fleisch) mit etwas Vitamin C (Paprika, Zitrus) kombinieren – das verbessert die Eisenaufnahme (zugelassene EU-Angabe). <b>Eisen</b> trägt zur Verringerung von Müdigkeit und Ermüdung bei."};
  } else if(bis<=5){
    phase="Lutealphase";
    hint={emoji:"🌙", title:"Kurz vor der Periode · noch ~"+bis+" Tage",
      text:"In dieser Phase sind mehr Hunger und <b>Heißhunger auf Süßes</b> sowie ein leicht höherer Energie- und <b>Magnesium</b>bedarf verbreitet. Vollkorn, Obst, Nüsse und dunkle Schokolade in Maßen können helfen."};
  }
  return {day, len, bis, phase, hint, nextStart};
}
