function mkLabel(m){ return (m && m.toLowerCase()!=="generisch") ? m : ""; }
function subLine(d){ const m=mkLabel(d.marke); return (m?esc(m)+" · ":"")+esc(d.kategorie||""); }
function prodLabel(p){ const m=mkLabel(p.marke); return p.name+(m?" · "+m:""); }
function betterAlt(d){
  const s=num(d.clean_score); if(s==null) return null;
  const STOP={fett:1,milch:1,bio:1,natur:1,ohne:1,mind:1,zucker:1,salz:1,wasser:1,'natürlich':1,gramm:1,vegan:1,protein:0};
  const toks=(d.name||"").toLowerCase().split(/[^a-zäöüß0-9]+/).filter(t=>t.length>=4 && !STOP[t]);
  if(!toks.length) return null;
  let best=null;
  (ALL||[]).forEach(q=>{
    if(q.id===d.id) return;
    const qs=num(q.clean_score); if(qs==null || qs < s+10) return;
    if(!(q.unterkategorie && d.unterkategorie && q.unterkategorie===d.unterkategorie)) return;
    const qn=(q.name||"").toLowerCase();
    if(!toks.some(t=>qn.includes(t))) return;
    if(!best || qs>num(best.clean_score)) best=q;
  });
  return best;
}
