/* ---- Amazon-Partnerprogramm (StoreID rootindex-21) ----
   NUR Deep-Links auf die Produkt-Detailseite. Amazon schreibt in den „Anforderungen für Links" vor:
   „Links, die für ein bestimmtes Produkt werben, müssen direkt auf die Detailseite für dieses
   Produkt auf der Amazon-Website geleitet werden."
   → Ein EAN-Suchlink ist damit NICHT zulässig, auch wenn er Provision brächte. Und eine ASIN wird
   nicht geraten. Ohne hinterlegten Amazon-Produktlink erscheint schlicht kein Button. */
const AMZ_TAG="rootindex-21";
function amazonUrl(d){
  if(!d) return "";
  const pl=String(d.produktlink||"");
  if(!/amazon\.[a-z.]+/i.test(pl)) return "";
  if(!/\/dp\/|\/gp\/product\//i.test(pl)) return "";
  try{ const u=new URL(pl); u.searchParams.set("tag",AMZ_TAG); return u.toString(); }catch(e){ return ""; }
}
function amazonBtn(d,klein){
  const u=amazonUrl(d); if(!u) return "";
  const pad=klein?"5px 9px":"7px 12px", fs=klein?"12px":"13px";
  return '<a href="'+u+'" target="_blank" rel="sponsored nofollow noopener" title="Anzeige · Amazon-Partnerlink"'
    +' style="display:inline-flex;align-items:center;gap:5px;padding:'+pad+';border:1px solid var(--k-e4a343);border-radius:8px;background:var(--k-fff7ea);color:var(--k-8a5a0b);text-decoration:none;font-size:'+fs+';font-weight:600;white-space:nowrap">'
    +'<span style="font-size:10px;font-weight:700;letter-spacing:.4px;opacity:.75">ANZEIGE</span> Bei Amazon</a>';
}
const AMZ_HINWEIS='<div style="font-size:11.5px;color:var(--muted);line-height:1.5;margin-top:8px">Anzeige: Als Amazon-Partner verdient Root&nbsp;Index an qualifizierten Verkäufen. Für dich ändert sich der Preis nicht – und der Root&nbsp;Index wird davon <b>nicht</b> beeinflusst.</div>';
/* Woher die Daten stammen – gehört sichtbar ins Produkt, sonst ist „Transparenz" eine Behauptung. */
function quellenBlock(d){
  const q=String(d.quelle||"").trim();
  const v=String(d.verifiziert||"").trim();
  const am=d.verifiziert_am?String(d.verifiziert_am).slice(0,10).split("-").reverse().join("."):"";
  if(!q) return "";
  const ungeprueft = (v!=="Ja") || /ungepr(ü|u)ft|unbest(ä|a)tigt/i.test(q);
  if(ungeprueft){
    return '<div style="margin-top:10px;background:var(--k-fff7ea);border:1px solid var(--k-e4a343);border-radius:12px;padding:10px 12px;font-size:12.5px;line-height:1.55;color:var(--k-8a5a0b)">'
      +'<b>⚠️ Diese Daten sind noch nicht verifiziert.</b><br>'
      +'Quelle: '+esc(q)+'. Wir zeigen den Index trotzdem – aber wir sagen dir, dass wir ihn noch nicht belegen können. '
      +'Du hast das Produkt zu Hause? Scanne es und fotografiere das Etikett, dann prüfen wir es.'
      +'</div>';
  }
  /* Die lange Lizenzangabe ("…, Max Rubner-Institut, CC BY 4.0") stand auf JEDER
     der 669 BLS-Karten. Das ist juristischer Text, kein Nutzertext - er gehoert
     EINMAL ins Impressum, nicht 669-mal auf die Karte. Auf der Karte bleibt der
     kurze Beleg (die Quelle + Pruefdatum) - unser staerkstes Argument, nur ohne
     das Kleingedruckte. Die volle Lizenz steht im Impressum (GL-24).
     quelleKurz() kuerzt nur BEKANNTE Langformen; alles andere bleibt unveraendert,
     damit nie ein Beleg versehentlich verschwindet. */
  return '<div style="margin-top:10px;background:var(--greenlt,var(--k-eaf5ee));border:1px solid var(--line);border-radius:12px;padding:10px 12px;font-size:12.5px;line-height:1.55;color:var(--ink)">'
    +'<b>✓ Datenquelle:</b> '+esc(quelleKurz(q))+(am?' · geprüft am '+esc(am):'')
    +'<div style="color:var(--muted);margin-top:3px">Jeder Punkt oben ist aus diesen Daten berechnet – nichts geschätzt. '
    +'<a onclick="legalOpen(\'impressum\')" style="color:var(--greendk);cursor:pointer;text-decoration:underline">Quellen &amp; Lizenzen</a></div>'
    +'</div>'+MED_HINWEIS;
}
/* Kuerzt die verbose Lizenz-Langform auf einen Nutzertext. Unbekanntes bleibt 1:1. */
function quelleKurz(q){
  var s=String(q||"");
  if(/bundeslebensmittelschl|BLS/i.test(s)) return 'Bundeslebensmittelschlüssel (BLS 4.0)';
  if(/open\s*food\s*facts/i.test(s))        return 'Open Food Facts';
  return s;
}
/* Kategorie-Einordnung: Ein Score ohne Maßstab verführt zu sinnlosen Vergleichen
   (Olivenöl 85 vs. Vollkornbrot 88 – niemand entscheidet zwischen den beiden).
   Deshalb: Platz innerhalb der eigenen Kategorie sichtbar machen. */
function katRang(d){
  if(!d||!d.kategorie||d.clean_score==null) return null;
  const gruppe=(ALL||[]).filter(function(x){ return x.kategorie===d.kategorie && x.clean_score!=null; });
  if(gruppe.length<3) return null;
  const sortiert=gruppe.slice().sort(function(a,b){ return num(b.clean_score)-num(a.clean_score); });
  const platz=sortiert.findIndex(function(x){ return x.id===d.id; })+1;
  if(platz<1) return null;
  const besser=sortiert.slice(0,platz-1).filter(function(x){ return num(x.clean_score)>num(d.clean_score); });
  return { platz:platz, gesamt:gruppe.length, kategorie:d.kategorie,
           top: sortiert.slice(0,3).filter(function(x){ return x.id!==d.id; }).slice(0,2) };
}
function katRangHtml(d){
  const r=katRang(d); if(!r) return "";
  const anteil=r.platz/r.gesamt;
  const farbe = anteil<=0.25 ? "var(--k-166534)" : (anteil<=0.6 ? "var(--k-8a5a0b)" : "var(--k-b45309)");
  const bg    = anteil<=0.25 ? "var(--greenlt,var(--k-eaf5ee))" : "var(--k-fff7ea)";
  const bd    = anteil<=0.25 ? "var(--line)" : "var(--k-e4a343)";
  return '<div style="margin-top:10px;background:'+bg+';border:1px solid '+bd+';border-radius:12px;padding:10px 12px;font-size:12.5px;line-height:1.55">'
    +'<b style="color:'+farbe+'">Platz '+r.platz+' von '+r.gesamt+' in „'+esc(r.kategorie)+'"</b>'
    +'<div style="color:var(--muted);margin-top:3px">Vergleiche den Index <b>innerhalb der Kategorie</b>. Ein Öl mit einem Brot zu vergleichen ergibt keinen Sinn – niemand entscheidet zwischen beidem. Ein Öl mit einem anderen Öl zu vergleichen schon.</div>'
    +(r.top.length?('<div style="margin-top:5px;color:var(--muted)">Vorne in dieser Kategorie: '
        +r.top.map(function(x){ return '<a href="#" onclick="event.preventDefault();detailById(\''+x.id+'\')" style="color:var(--greendk,var(--k-166534));font-weight:600;text-decoration:none">'+esc(x.name)+' ('+x.clean_score+')</a>'; }).join(' · ')+'</div>'):'')
    +'</div>';
}
/* GL-5: Haftungsausschluss sichtbar dort, wo bewertet wird – nicht nur im Kleingedruckten. */
const MED_HINWEIS='<div style="margin-top:8px;font-size:11.5px;color:var(--muted);line-height:1.5">Der Root Index bewertet <b>Zusammensetzung und Verarbeitungsgrad</b> eines Lebensmittels. Er ist keine Aussage darüber, ob ein Produkt für <b>dich persönlich</b> geeignet ist, und ersetzt <b>keine ärztliche oder ernährungstherapeutische Beratung</b>. Bei Beschwerden, Allergien, Erkrankungen, Schwangerschaft oder Medikamenteneinnahme: bitte ärztlich abklären.</div>';
