function _norm(s){ return (s||"").toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g,""); }
function _lev(a,b){ const m=a.length,n=b.length; if(!m)return n; if(!n)return m; let prev=Array.from({length:n+1},(_,j)=>j),cur=new Array(n+1);
  for(let i=1;i<=m;i++){ cur[0]=i; for(let j=1;j<=n;j++){ cur[j]=Math.min(prev[j]+1,cur[j-1]+1,prev[j-1]+(a[i-1]===b[j-1]?0:1)); } const t=prev;prev=cur;cur=t; } return prev[n]; }
/* ===========================================================================
   SUCHE — "ei" traf 642 von 1034 Produkten. Fast zwei Drittel des Katalogs.
   Ursache: t.includes(q) trifft MITTEN im Wort. In "ei" stecken W-ei-zen,
   Fl-ei-sch, R-ei-s, Br-ei, G-ei-treide, B-ei-lagen. Die Kategorie wurde
   mitgesucht - und fast jede Kategorie enthaelt "ei".

   > Je kuerzer der Suchbegriff, desto genauer muss er sitzen.

   Kurze Begriffe (1-3 Zeichen) matchen nur noch am WORTANFANG. Damit findet
   "ei" das Ei, aber nicht den Weizen. Ab 4 Zeichen bleibt die Suche mitten im
   Wort erlaubt - sonst faende "milch" die "Vollmilch" nicht mehr.
   =========================================================================== */
function _wortAnfang(t,q){
  // Wortanfang = Zeichenkette beginnt, oder davor steht etwas, das kein Buchstabe ist
  const i=t.indexOf(q);
  if(i<0) return false;
  let k=i;
  while(k>=0){
    if(k===0) return true;
    if(!/[a-z0-9äöüß]/.test(t[k-1])) return true;
    k=t.indexOf(q,k+1);
    if(k<0) return false;
  }
  return false;
}
function _fuzzy(text,q){
  const t=_norm(text); if(!q) return true;
  if(q.length<=3) return _wortAnfang(t,q);   // "ei", "bio", "k2" - nur am Wortanfang
  if(t.includes(q)) return true;             // ab 4 Zeichen: "milch" findet "Vollmilch"
  const max=q.length<=5?1:2;
  return t.split(/[^a-z0-9]+/).some(w=> w.length>2 && (w.includes(q) || _lev(w,q)<=max));
}
/* Ein Produkt matchen - inklusive der gepflegten Synonyme.
   Ohne das ist jeder Synonym-Eintrag Arbeit ohne Wirkung: "Ei" steht in
   Suchbegriffe_Synonyme, aber niemand hat je hineingesehen.
   Die Kategorie wird bei KURZEN Begriffen NICHT durchsucht - sie war der
   Haupttreiber der 642 Falschtreffer. */
function _prodMatch(p,q){
  if(!q) return true;
  const syn=Array.isArray(p.synonyme)?p.synonyme:[];
  if(syn.some(s=>_norm(s)===q)) return true;                 // exaktes Synonym: "ei"
  if(_fuzzy(p.name,q) || _fuzzy(p.marke,q)) return true;
  if(syn.some(s=>_fuzzy(s,q))) return true;
  if(q.length>=4 && _fuzzy(p.kategorie,q)) return true;      // Kategorie erst ab 4 Zeichen
  return false;
}
/* Relevanz statt Score: Vorher sortierte die Trefferliste nach Clean-Score.
   Selbst wenn "Ei" traf, stand es hinter allem, was 100 Punkte hatte. */
function _relevanz(p,q){
  if(!q) return 0;
  const n=_norm(p.name||""), m=_norm(p.marke||"");
  const syn=(Array.isArray(p.synonyme)?p.synonyme:[]).map(_norm);
  if(n===q || syn.includes(q))       return 100;   // "ei" -> Ei (roh)
  if(_wortAnfang(n,q))               return 80;    // "hafer" -> Haferflocken
  if(syn.some(s=>_wortAnfang(s,q)))  return 70;
  if(n.includes(q))                  return 50;    // "milch" -> Vollmilch
  if(_wortAnfang(m,q)||m.includes(q))return 40;    // Marke
  return 10;                                        // nur noch unscharf
}
function render(){
  const rawQ=document.getElementById("q").value.trim();
  const q=_norm(rawQ);
  const kat=window._prodKat||"";
  const grid=document.getElementById("grid");
  if(!q && !kat && !window._prodShowAll){
    document.getElementById("stats").textContent="";
    grid.innerHTML=katKachelnHtml();
    return;
  }
  let list=ALL.filter(d=>{
    if(kat && d.kategorie!==kat)return false;
    if(q && !_prodMatch(d,q))return false;
    return true;
  });
  /* Suche mitzaehlen - aber ERST wenn der Nutzer aufgehoert hat zu tippen (1 s),
     sonst laende jeder Tastendruck ("m","ma","man"...) als eigener Begriff.
     Gezaehlt wird der fertige Begriff + die Trefferzahl. 0 Treffer = Katalog-Luecke. */
  if(rawQ){
    clearTimeout(window._sucheLogTimer);
    const _b=rawQ, _n=list.length;
    window._sucheLogTimer=setTimeout(function(){
      try{ client.rpc("cb_log_suche",{p_begriff:_b, p_treffer:_n}).then(function(){},function(){}); }catch(e){}
    }, 1000);
  }
  // Bei einer Suche zaehlt Relevanz zuerst, erst danach der Score.
  // Ohne Suche (Kategorie-Ansicht) bleibt es beim Score.
  if(q) list.sort((a,b)=> (_relevanz(b,q)-_relevanz(a,q)) || ((b.clean_score??-1)-(a.clean_score??-1)));
  else  list.sort((a,b)=> (b.clean_score??-1)-(a.clean_score??-1));
  if(kat) document.getElementById("stats").innerHTML='<span onclick="prodKatReset()" style="cursor:pointer;color:var(--greendk,var(--k-166534));font-weight:600">‹ Kategorien</span> · '+esc(kat)+' · '+list.length+' Produkt(e)';
  else document.getElementById("stats").textContent=list.length+" Produkt(e)";
  grid.innerHTML="";
  list.forEach((d,i)=>{
    const c=document.createElement("div");c.className="card cardIn";c.onclick=()=>detail(d);
    // Gestaffeltes Einblenden: nur die ersten 12, danach waere die Verzoegerung
    // laenger als die Geduld. Nur transform+opacity - beides laeuft auf der GPU.
    c.style.animationDelay=(Math.min(i,11)*40)+"ms";
    c.innerHTML=`
      ${scoreLead(d, 62)}
      <div class="meta">
        <div class="name">${esc(d.name)}</div>
        <div class="sub">${subLine(d)}</div>
        ${statusTag(d)}${efChip(d.ernaehrungsform)}
      </div>`;
    grid.appendChild(c);
  });
}
