function katKachelnHtml(){
  var items=(window._KATLIST||[]);
  if(!items.length) return '';
  var tiles=items.map(function(o){
    var m=katMeta(o.k), k=esc(o.k);
    /* min-width:0 ist PFLICHT. Ein Grid-Item hat von Haus aus min-width:auto -
       ein langer Name wie "Tofu & Fleischalternativen" druckt die Spalte dann
       breiter als ihr 1fr erlaubt. Die Seite wird breiter als das Fenster,
       scrollt seitlich, und der fensterbreite Kopfbalken endet vor dem Rand.
       > Ein Fehler, zwei Symptome. */
    return '<button data-kat="'+k+'" onclick="prodKatPick(this.dataset.kat)" style="all:unset;box-sizing:border-box;min-width:0;overflow:hidden;cursor:pointer;background:var(--card,var(--k-ffffff));border:1px solid var(--line,var(--k-e7e0d4));border-radius:12px;padding:12px;display:flex;align-items:center;gap:10px">'
      +'<span style="width:34px;height:34px;border-radius:50%;background:'+m.bg+';color:'+m.fg+';display:flex;align-items:center;justify-content:center;font-size:18px;flex:0 0 auto">'+m.e+'</span>'
      +'<span style="min-width:0"><span style="display:block;font-size:14px;color:var(--ink,var(--k-1d3c24));white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+k+'</span>'
      +'<span style="font-size:12px;color:var(--muted,var(--k-6b6256))">'+o.n+'</span></span></button>';
  }).join('');
  return '<div style="grid-column:1/-1;width:100%;box-sizing:border-box;max-width:760px;margin:0 auto">'
    +'<div style="font-size:14px;color:var(--muted,var(--k-6b6256));margin:2px 2px 10px">Kategorie wählen oder oben suchen &amp; Barcode scannen.</div>'
    +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">'+tiles+'</div>'
    +'<button onclick="window._prodShowAll=true;render()" style="width:100%;box-sizing:border-box;margin-top:10px;padding:12px;border:1px solid var(--green);border-radius:10px;background:var(--greenlt,var(--k-eaf5ee));color:var(--greendk,var(--k-166534));cursor:pointer;font-size:14px">Alle '+ALL.length+' Produkte anzeigen</button>'
    +'</div>';
}
function prodKatPick(k){ window._prodKat=k; window._prodShowAll=false; var qi=document.getElementById("q"); if(qi) qi.value=""; render(); try{ window.scrollTo({top:0,behavior:"smooth"}); }catch(e){ window.scrollTo(0,0); } }
function prodKatReset(){ window._prodKat=""; window._prodShowAll=false; var qi=document.getElementById("q"); if(qi) qi.value=""; render(); try{ window.scrollTo({top:0,behavior:"smooth"}); }catch(e){ window.scrollTo(0,0); } }
function zInfoClean(name, info){
  let s = String(info||"").replace(/\s*\((?:KI\s*)?Stufe\s*\d+\)/gi,"").replace(/\s{2,}/g," ").trim();
  s = s.replace(/[–-]\s*$/,"").replace(/\.\s*$/,"").trim();
  const n = String(name||"").trim().replace(/\.$/,"");
  if(!s) return "";
  if(s.toLowerCase()===n.toLowerCase()) return "";      // redundant (nur Name wiederholt)
  return s;
}
