    const R=SCORE_REGELN[it.short]||{farbe:ACHS_FARBE.zutaten,regel:"",quelle:""};
    const pct=Math.max(0,Math.min(100,(it.v/it.max)*100));
    const voll=(it.v >= it.max-0.01);
    const id="sfx"+i;
    achsen+='<div style="border:1px solid var(--line);border-radius:10px;background:var(--card);margin-bottom:6px;overflow:hidden">'
