            +'<div class="suCnt" data-ziel="'+wk+'" style="font-size:27px;font-weight:800;line-height:1;color:var(--ink)">'+wk+'</div>'
            +'<div style="font-size:11px;color:var(--muted);margin-top:1px">von '+g+'</div>'
          +'</div>'
