          +'<div style="font-size:11px;color:var(--muted);line-height:1.6"><span style="color:var(--ri-gruen)">■</span> '+wk+' mit belegtem EU-Nutzen (≥ 15 % Tagesbedarf)'+xtra+'</div>'
        +'</div>'
      +'</div>'
