      +urows
      +'<div style="font-size:10.5px;color:var(--muted);line-height:1.5;margin-top:9px">Von der EU zugelassene Aussagen zur normalen Körperfunktion (VO 432/2012). Keine Aussage zu Beschwerden oder Krankheiten.</div>'
    +'</div>';
