function detail(d){
  /* Aufruf mitzaehlen (fire-and-forget, blockiert die Anzeige nie). Aggregierter
     Tageszaehler pro Produkt - keine Nutzer-Verknuepfung. Zeigt den Schwerpunkt:
     welche Produkte oeffnen die Leute wirklich. */
  /* .then() ist PFLICHT: der Supabase-Builder ist faul - ohne await oder .then
     wird die Anfrage NIE gesendet. "Fire and forget" heisst trotzdem: erst zuenden. */
  /* 2026-07-19m: Der neue Karten-Entwurf (detail2) ist jetzt die Hauptansicht fuer ALLE.
     detail2 protokolliert den Aufruf selbst (cb_log_aufruf) - daher hier NICHT nochmal
     loggen, sonst zaehlt jeder Aufruf doppelt. Die alte Karte darunter laeuft nicht mehr;
     sie bleibt vorerst nur als toter Code stehen (Sicherheitsnetz), kann spaeter raus. */
  try{ return detail2(d); }catch(e){ console.log("detail2 fehlgeschlagen, alte Karte:", e); }
  var _isScoredFood=(d.clean_score!=null && String(d.kategorie||'').toLowerCase()!=='supplement');
  var _adminHere=(typeof ME!=='undefined' && ME && ME.is_admin);
  var adminTestBtn=(_adminHere && _isScoredFood)?'<div style="margin:2px 0 8px"><button onclick="detail2(ALL.find(function(x){return x.id===\''+d.id+'\'}))" style="padding:5px 10px;border:1px dashed var(--line);border-radius:8px;background:var(--bg);color:var(--muted);font-size:12px;cursor:pointer">🔬 Karten-Entwurf ansehen</button></div>':'';
  var _bz=bzStufe(d);
  var bzBlock=_bz?('<div style="font-size:11px;text-transform:uppercase;letter-spacing:.5px;color:var(--green);margin:18px 0 6px;display:flex;justify-content:space-between;align-items:center"><span>Blutzucker-Verlauf</span><span style="font-size:11.5px;padding:3px 9px;border-radius:20px;background:'+_bz.bg+';color:'+_bz.tc+'">'+_bz.label+'</span></div>'+bzKurve(_bz.stufe)):'';
  const col=farbe(d.bewertung);
  const _isOil=((d.kategorie||'')==='Öle & Fette'), _isZero=(num(d.m_kcal)===0);
  const sonderHint = (_isOil||_isZero) ? `<div style="font-size:12.5px;line-height:1.45;margin:8px 0 2px;padding:8px 11px;background:var(--k-eef6ff);border:1px solid var(--k-cfe3f7);border-radius:9px;color:var(--k-1e3a8a)">ℹ️ <b>Sonderbewertung:</b> ${_isOil?'Bei Ölen &amp; Fetten zählt die <b>Fettqualität</b> (Anteil ungesättigter Fettsäuren) statt des Makro-Profils pro 100 g.':'<b>0‑kcal-Produkt</b> – der Nährwert-Teil entfällt; bewertet werden Zutaten, Verarbeitung &amp; Zusatzstoffe.'}</div>` : '';
  const mkRows = arr => arr.map(([k,label,max,mult])=>{
    const m=mult||1; const raw=num(d[k]); const v=raw===null?null:raw*m;
    const pct=v===null?0:Math.max(0,Math.min(100,(v/max)*100));
    return `<div class="row"><div class="top"><b>${label}</b><span>${v===null?"– n/a":v+" / "+max}</span></div>
      <div class="track"><div class="fill" style="width:${pct}%;${v===null?'background:var(--k-d5ded8)':''}"></div></div></div>`;
  }).join("");
  const mkRings = arr => {
    /* Zweite Farbtabelle - sie zeichnet die RINGE. Sie hatte ihre eigenen Werte,
       obwohl SCORE_REGELN dieselben Farben schon fuehrte. Jetzt beide aus ACHS_FARBE:
       eine Quelle, sonst laufen sie beim naechsten Fix wieder auseinander. */
    const COL={Zutaten:ACHS_FARBE.zutaten,Zusatzstoffe:ACHS_FARBE.zusatz,Verarbeitung:ACHS_FARBE.nova,"Nährwert":ACHS_FARBE.naehr};
    const items=arr.map(([k,label,max,mult,short])=>{ const m=mult||1; const raw=num(d[k]); const v=raw===null?null:raw*m; const pct=v===null?null:Math.max(0,Math.min(1,v/max)); return {short:short||label,max,v,pct,col:COL[short]||ACHS_FARBE.zutaten}; }).filter(it=>it.pct!==null);
    if(!items.length) return "";
    let rings=""; const sw=7;
    items.forEach((it,i)=>{ const r=52-i*11; const C=2*Math.PI*r; const off=(C*(1-it.pct)).toFixed(1); rings+='<circle cx="65" cy="65" r="'+r+'" fill="none" stroke="var(--line)" stroke-width="'+sw+'"/><circle cx="65" cy="65" r="'+r+'" fill="none" stroke="'+it.col+'" stroke-width="'+sw+'" stroke-linecap="round" stroke-dasharray="'+C.toFixed(1)+'" stroke-dashoffset="'+off+'" transform="rotate(-90 65 65)"/>'; });
    /* "Zusatzstoffe" lief unter die Prozentzahl: das Label hatte flex:1 und min-width:0,
       aber KEIN overflow. Ein flex:1-Element darf schrumpfen - es muss aber auch
       abschneiden duerfen, sonst schiebt es sich unter den Nachbarn.
       Die Zahlen bekommen flex:0 0 auto: sie geben nie Platz her. */
    const legend=items.map(it=>'<div style="display:flex;align-items:center;gap:8px;font-size:12.5px">'
      +'<span style="width:10px;height:10px;border-radius:2px;background:'+it.col+';flex:0 0 auto"></span>'
      +'<span style="color:var(--muted);flex:1 1 auto;min-width:0;line-height:1.2">'+esc(it.short)+'</span>'
      +'<b style="flex:0 0 auto">'+Math.round(it.pct*100)+'%</b>'
      +'<span style="color:var(--muted);font-size:11px;flex:0 0 auto;white-space:nowrap">'+String(Math.round(it.v*10)/10).replace(".",",")+"/"+it.max+'</span>'
      +'</div>').join("");
    /* Der Ring skaliert mit dem Platz (min 92, max 130 px) - auf einem schmalen
       Handy nimmt er sich weniger, damit die Legende ihre Woerter ausschreiben kann. */
    return '<div style="display:flex;align-items:center;gap:14px;flex-wrap:wrap;margin:6px 0">'
      +'<svg viewBox="0 0 130 130" style="width:clamp(92px,26vw,130px);height:clamp(92px,26vw,130px);flex:0 0 auto" role="img" aria-label="Index-Aufschlüsselung"><title>Root Index Aufschlüsselung</title>'+rings+'</svg>'
      +'<div style="flex:1 1 160px;min-width:0;display:flex;flex-direction:column;gap:7px">'+legend+'</div></div>';
  };
  const rows = mkRings(SCORE_TEIL);
  const mkAbzug = arr => {
    const REASON={Zutaten:"Zutaten nicht durchweg als Vollwert bewertet",Zusatzstoffe:"enthält Zusatzstoffe",Verarbeitung:"höherer Verarbeitungsgrad","Nährwert":"Nährwertprofil pro 100 g (Zucker, Fett, Salz, Ballaststoffe, Eiweiß)"};
    const items=arr.map(([k,label,max,mult,short])=>{const m=mult||1;const raw=num(d[k]);const v=raw===null?null:raw*m;return {short:short||label,max,v};}).filter(it=>it.v!==null && it.v < it.max-0.01);
    if(!items.length) return "";
    const lines=items.map(it=>{
      const lost=Math.round((it.max-it.v)*10)/10;
      return '<div style="display:flex;gap:10px;padding:8px 0;border-top:1px solid var(--line)"><span style="flex:0 0 96px;font-weight:600;font-size:13px">'+esc(it.short)+'</span><span style="flex:1;min-width:0;font-size:12.5px;color:var(--muted);line-height:1.4">'+esc(REASON[it.short]||"")+' <span style="white-space:nowrap;color:var(--k-dc2626)">(&minus;'+String(lost).replace(".",",")+')</span></span></div>';
    }).join("");
    return '<div style="font-size:11px;text-transform:uppercase;letter-spacing:.5px;color:var(--green);margin:16px 0 4px">Warum nicht die volle Punktzahl?</div>'+lines;
  };
  const abzug = mkAbzug(SCORE_TEIL);
  const zlist = Array.isArray(d.zutaten) ? d.zutaten : [];
  const neutralZ = d.zusatz && /neutral|technolog|unbedenk/i.test(String(d.zusatz.status||""));
  const zHtml = zlist.length ? zlist.map(z=>{
    const krit = (String(z.kritisch||"")).toLowerCase()==="ja";
    const isCoag = neutralZ && /koagulation|gerinnung|calciumsulfat|calciumchlorid|magnesiumchlorid|nigari|e516|e509|e511/i.test(String(z.name||""));
    let bg = krit?"var(--k-fde8e8)":(z.rating>=8?"var(--k-e7f4ec)":(z.rating>=5?"var(--k-fff7e6)":"var(--k-fde8e8)"));
    let tc = krit?"var(--k-b91c1c)":(z.rating>=8?"var(--k-1f5e34)":(z.rating>=5?"var(--k-92400e)":"var(--k-b91c1c)"));
    if(isCoag){ bg="var(--k-eef6ff)"; tc="var(--k-1e3a8a)"; }
    return `<span style="display:inline-block;margin:3px 3px 0 0;padding:4px 10px;border-radius:999px;font-size:12px;background:${bg};color:${tc}">${esc(z.name)}${krit?" ⚠️":""}${isCoag?" *":""}</span>`;
  }).join("") : '<span style="color:var(--muted);font-size:13px">keine Zutaten hinterlegt</span>';
  const mRows = MACROS.filter(([k])=>d[k]!==null && d[k]!==undefined).map(([k,label,unit])=>{
    const raw=num(d[k]); const val=(k==="m_kcal")?Math.round(raw):Math.round(raw*10)/10;
    let vc="", extra="";
    if(k==="m_ges_fett"){
      vc="color:var(--k-dc2626)"; // gesättigte Fettsäuren = rot
      const fett=num(d.m_fett); const uns=(fett!=null&&raw!=null)?Math.round((fett-raw)*10)/10:null;
      if(uns!=null && uns>=0) extra=`<div style="display:flex;justify-content:space-between;font-size:13px;padding:4px 0;border-bottom:1px solid var(--line)"><span>– davon ungesättigte</span><span style="font-weight:600;color:var(--k-16a34a)">${uns} ${unit}</span></div>`;
    }
    return `<div style="display:flex;justify-content:space-between;font-size:13px;padding:4px 0;border-bottom:1px solid var(--line)"><span>${label}</span><span style="font-weight:600;${vc}">${val} ${unit}</span></div>`+extra;
  }).join("");
  const variants = ALL.filter(x=>x.variante_von===d.id);
  let varNote="";
  if(variants.length) varNote = "Auch erhältlich: "+variants.map(v=>esc(v.name)).join(", ");
  else if(d.variante_von){ const base=ALL.find(x=>x.id===d.variante_von); if(base) varNote="Variante von: "+esc(base.name); }
  const _sd = hasFeat('score_detail');
  const zInfoHtml = (()=>{const infos=zlist.map(z=>({z,t:zInfoClean(z.name,z.info)})).filter(o=>o.t);return infos.length?`<div style="margin-top:8px">${infos.map(o=>`<div style="font-size:12.5px;line-height:1.45;margin:6px 0;padding:8px 11px;background:var(--bg);border:1px solid var(--line);border-radius:9px"><b>${esc(o.z.name)}</b>${(String(o.z.kritisch||'')).toLowerCase()==='ja'?' ⚠️':''}: ${esc(o.t)}</div>`).join("")}</div>`:"";})();
  var _ztxt=((zlist||[]).map(function(z){return z.name||'';}).join(' '))+' '+((d.zusatz&&d.zusatz.text)||'')+' '+(d.zusatzstoffe_text||'');
  var _azoWarn=/\be ?(102|104|110|122|124|129)\b|tartrazin|chinolingelb|gelborange|azorubin|cochenillerot|allurarot/i.test(_ztxt);
  // Supplements bekommen KEINEN Lebensmittel-Score (Kapsel hat keine Naehrwerte -> die
  // fehlende 40-Punkte-Achse wuerde den Score kuenstlich anheben). Reinheits-Index folgt.
  var _istSupp=(String(d.kategorie||'').toLowerCase()==='supplement') && d.clean_score==null;
  var _ksuessWarn=(String(d.suessstoffe||'')==='ja_kuenstlich')||/sucralose|acesulfam|aspartam|cyclamat|saccharin|\be ?9(5[0-9]|62)\b/i.test(_ztxt);
  /* ---------------------------------------------------------------------
     SUPPLEMENT-ZUSAMMENFASSUNG: drei GETRENNTE Aussagen, keine addierte Note.
     Warum keine Summe: Die Nährwert-Achse (40 Pkt) ist bei einer Kapsel leer,
     Zusatzstoffe und Verarbeitung sind über fast alle Präparate konstant -
     nur Zutatenqualität variiert. Eine Summe daraus wäre eine Zahl, die
     präzise aussieht und nichts weiß (§1.11v-c). Zuoberst die Bezugsmenge:
     ohne sie weiß niemand, ob die Werte für eine Kapsel oder für drei gelten.
     --------------------------------------------------------------------- */
  var suppSummary='';
  if(_istSupp){
    var _sq=num(d.p_zutaten), _sz=num(d.p_zusatzstoffe);
    var _dose=(d.dosis_text && String(d.dosis_text).trim()) ? String(d.dosis_text).trim() : '';
    var _chip=function(txt,bg,fg){ return '<span style="display:inline-block;font-size:11.5px;padding:3px 9px;border-radius:20px;background:'+bg+';color:'+fg+'">'+txt+'</span>'; };
    var _zeilen='';
    if(_sq!=null){
      var _p=Math.max(0,Math.min(100,_sq/30*100));
      _zeilen+='<div style="display:flex;justify-content:space-between;align-items:center;gap:10px;padding:9px 12px;border-bottom:1px solid var(--line)">'
        +'<span style="font-size:12.5px;color:var(--ink)">Zutatenqualität</span>'
        +'<span style="display:flex;align-items:center;gap:9px">'
          +'<span style="display:inline-block;width:80px;height:6px;border-radius:99px;background:var(--line);overflow:hidden"><i style="display:block;height:100%;width:'+_p+'%;background:var(--k-7ba05b);border-radius:99px"></i></span>'
          +'<span style="font-size:12.5px;font-weight:600;color:var(--ink);white-space:nowrap">'+String(Math.round(_sq*10)/10).replace('.',',')+' / 30</span>'
        +'</span></div>';
    }
    if(_sz!=null){
      var _rein=(_sz>=15);
      _zeilen+='<div style="display:flex;justify-content:space-between;align-items:center;gap:10px;padding:9px 12px">'
        +'<span style="font-size:12.5px;color:var(--ink)">Zusatzstoffe</span>'
        +(_rein?_chip('keine','var(--k-e7f4ec)','var(--k-1f5e34)'):_chip('enthalten','var(--k-fff7e6)','var(--k-92400e)'))
        +'</div>';
    }
    suppSummary='<div style="display:flex;gap:7px;flex-wrap:wrap;margin:2px 0 10px">'
      + _chip('Kein Root Index','var(--k-f0ece3)','var(--k-57534e)')
      + (_dose ? _chip(esc(_dose),'var(--k-eef6ff)','var(--k-1e3a8a)')
               : _chip('Tagesdosis nicht erfasst','var(--k-f4f5f4)','var(--muted)'))
      + '</div>'
      + (_zeilen ? '<div style="border:1px solid var(--line);border-radius:12px;overflow:hidden;margin-bottom:10px">'+_zeilen+'</div>' : '');
  }
  /* FREI für alle: die Herleitung. „Vertrauen vor Umsatz" – das Warum ist kein Premium-Feature,
     es ist der Beweis, dass wir nichts erfinden. Premium sind die persönlichen Werkzeuge. */
  /* Die Produktkarte besteht aus fuenf Bloecken. Welcher Block auf welcher Stufe
     sichtbar ist, steht in der DB (Adminbereich > Premium-Stufen), NICHT hier im Code:
       Block 1  der Index          - immer frei, das ist das Versprechen der App
       Block 2  Naehrwerte         - pk_naehrwerte
       Block 3  Im Root Index      - pk_ringe
       Block 4  So kommt er zustande - pk_regeln
       Block 5  Platzierung        - pk_platzierung
     > Eine Regel, die nur im Code steht, kann man nicht aendern, ohne zu deployen. */
  const warumBlock = `
    ${hasFeat('pk_ringe') ? `
      <div style="font-size:11px;text-transform:uppercase;letter-spacing:.5px;color:var(--green);margin:16px 0 4px">Im Root Index</div>
      ${sonderHint}
      ${rows}
      ${abzug}` : pkSperre('Im Root Index','Die vier Achsen mit Punkten')}
    ${hasFeat('pk_regeln')      ? scoreFlow(d)    : pkSperre('So kommt der Index zustande','Regeln, Deckel-Check und Herleitung')}
    ${hasFeat('pk_platzierung') ? katRangHtml(d)  : pkSperre('Platzierung','Platz in der Kategorie und die Besten')}
    ${quellenBlock(d)}
  `;
  /* PREMIUM: die Zutaten-Einzelbewertung im Detail (Herleitung bleibt frei, s. warumBlock) */
  const zutatenBlock = `
    <div style="font-size:11px;text-transform:uppercase;letter-spacing:.5px;color:var(--green);margin:18px 0 6px">Zutaten</div>
    <div style="font-size:11px;color:var(--muted);margin-bottom:6px"><span style="display:inline-block;width:9px;height:9px;border-radius:2px;background:var(--k-1f5e34);margin-right:3px"></span>gut (Vollwert) &nbsp;<span style="display:inline-block;width:9px;height:9px;border-radius:2px;background:var(--k-e8920c);margin-right:3px"></span>mittel (verarbeitet) &nbsp;<span style="display:inline-block;width:9px;height:9px;border-radius:2px;background:var(--k-dc2626);margin-right:3px"></span>stark verarbeitet</div>
    <div>${zHtml}</div>
    ${(d.zusatz && d.zusatz.info && /neutral|technolog|unbedenk/i.test(String(d.zusatz.status||"")))?`<div style="margin-top:8px;font-size:12.5px;line-height:1.45;padding:8px 11px;background:var(--k-eef6ff);border:1px solid var(--k-cfe3f7);border-radius:9px;color:var(--k-1e3a8a)"><b>* ${esc(d.zusatz.text||"Zusatzstoff")}</b> – technologisch notwendig &amp; unbedenklich, zählt nicht negativ. ${esc(d.zusatz.info)}</div>`:""}
    ${d.warum?`<div class="note"><h4>Warum empfohlen</h4>${esc(d.warum)}</div>`:""}
    ${d.schwaechen?`<div class="note teilhint"><h4>Schwächen</h4>${esc(d.schwaechen)}</div>`:""}
  `;
  /* Sanfter Hinweis statt Mauer. Dieser Text LISTETE frueher fest auf, was frei sei
     ("der Index, die vier Achsen, jede Regel, jede Quelle - alles, was du oben siehst").
     Sobald die Bloecke aber im Adminbereich umschaltbar wurden, wurde der Satz zur Luege:
     man konnte einen Block sperren, und der Text behauptete weiter, er sei frei.
     > Ein Werbetext, der die eigene Einstellung nicht kennt, wird zum Wortbruch.
     Jetzt liest er denselben Freischalt-Stand wie die Karte darueber. */
  const _frei=['der Index'];
  if(hasFeat('pk_ringe'))       _frei.push('die vier Achsen');
  if(hasFeat('pk_naehrwerte'))  _frei.push('die Nährwerte');
  if(hasFeat('pk_regeln'))      _frei.push('jede Regel');
  if(hasFeat('pk_platzierung')) _frei.push('die Platzierung');
  _frei.push('jede Quelle');   // quellenBlock ist immer sichtbar
  const _extra=[];
  if(!hasFeat('pk_naehrwerte'))  _extra.push('die Nährwerte');
  if(!hasFeat('pk_ringe'))       _extra.push('die vier Achsen');
  if(!hasFeat('pk_regeln'))      _extra.push('die Herleitung');
  if(!hasFeat('pk_platzierung')) _extra.push('die Platzierung');
  _extra.push('die <b>Bewertung jeder einzelnen Zutat</b>','deine <b>Tagesbedarfs-Deckung</b>','<b>bessere Alternativen</b> sowie Ernährungstagebuch, Trainingsplaner und Rezepte');
  function _undListe(a){ return a.length<2 ? (a[0]||'') : a.slice(0,-1).join(', ')+' und '+a[a.length-1]; }
  const _freiTitel = ME ? 'In deinem Konto frei:' : 'Frei – ohne Konto:';
  const _extraTitel = ME ? 'Mit Premium zusätzlich:' : 'Mit Konto / Premium zusätzlich:';
  const upsellBlock = `
    <div style="margin-top:14px;background:var(--card);border:1px solid var(--line);border-radius:12px;padding:13px 14px">
      <div style="font-weight:700;margin-bottom:6px;font-size:14px">Die Bewertung ist und bleibt kostenlos.</div>
      <div style="font-size:12.5px;color:var(--muted);line-height:1.6;margin-bottom:10px">
        <b style="color:var(--greendk,var(--k-166534))">${_freiTitel}</b> ${_undListe(_frei)}.<br>
        <b style="color:var(--ink)">${_extraTitel}</b> ${_undListe(_extra)}.
      </div>
      <button onclick="${ME?'premiumInfo()':'openLogin()'}" style="padding:9px 16px;border:1px solid var(--green);border-radius:10px;background:var(--greenlt);color:var(--greendk);font-weight:600;cursor:pointer;font-size:13px">${ME?'Premium ansehen – 7 Tage gratis':'7 Tage gratis testen'}</button>
    </div>
  `;
  const panel=document.getElementById("panel");
  panel.innerHTML=`
    <button class="close" onclick="closeP()">Schließen ✕</button>
    ${adminTestBtn}
    <h2>${esc(d.name)}</h2>
    <div class="marke">${(mkLabel(d.marke)?esc(mkLabel(d.marke))+" · ":"")}${esc(d.kategorie||"")}${d.unterkategorie?(" · "+esc(d.unterkategorie)):""} ${efChip(d.ernaehrungsform)}</div>
    <div style="margin:8px 0;display:flex;gap:8px;flex-wrap:wrap;align-items:center"><button onclick="prodToEinkauf('${d.id}')" style="padding:7px 12px;border:1px solid var(--green);border-radius:8px;background:var(--greenlt);color:var(--greendk);cursor:pointer;font-size:13px;font-weight:600">🛒 Zur Einkaufsliste</button>${amazonBtn(d)}${(ME&&ME.is_admin)?`<button onclick="adminDeleteProdukt('${d.id}','${esc(d.name||"").replace(/'/g,"")}')" style="padding:7px 12px;border:1px solid var(--k-fca5a5);border-radius:8px;background:var(--card);color:var(--k-dc2626);cursor:pointer;font-size:13px">🗑️ Produkt ausblenden</button>`:""}</div>
    ${amazonUrl(d)?AMZ_HINWEIS:""}
    ${BILD[d.id]?`<div style="text-align:center;margin:8px 0"><img src="${esc(BILD[d.id])}" alt="" style="max-height:170px;max-width:100%;border-radius:12px" onerror="this.style.display='none'"></div>`:""}
    ${(d.dosis_text||d.inhalt_menge)?`<div style="background:var(--greenlt);border:1px solid var(--line);border-radius:10px;padding:8px 12px;margin:8px 0;font-size:13px;color:var(--ink);line-height:1.5">${d.dosis_text?`<div><b>Angegebene Dosis:</b> ${esc(d.dosis_text)}</div>`:""}${d.inhalt_menge?`<div><b>Inhalt:</b> ${esc(String(d.inhalt_menge).replace(/\.0+$/,""))}${d.inhalt_einheit?(" "+esc(d.inhalt_einheit)):""}${d.form?(" · "+esc(d.form)):""}</div>`:""}</div>`:""}
    ${varNote?`<div class="note" style="background:var(--k-eef6ff);border-color:var(--k-cfe3f7);color:var(--k-1e3a8a)">↔ ${varNote}</div>`:""}
    ${_istSupp ? `
    <div style="display:flex;gap:14px;align-items:center;margin:10px 0">
      <svg width="54" height="54" viewBox="0 0 52 52" style="flex:0 0 auto" role="img" aria-label="Nahrungsergänzung">
        <title>Nahrungsergänzung – kein Lebensmittel-Index</title>
        <rect x="17" y="6" width="18" height="40" rx="9" fill="var(--k-f0ece3)" stroke="var(--k-d8d2c6)" stroke-width="1.5"/>
        <line x1="17" y1="26" x2="35" y2="26" stroke="var(--k-d8d2c6)" stroke-width="1.5"/>
      </svg>
      <div style="flex:1;min-width:0">
        <div style="font-size:16px;font-weight:800;color:var(--ink);line-height:1.25">Kein Lebensmittel-Index</div>
        <div style="font-size:12.5px;color:var(--muted);line-height:1.45;margin-top:2px">Eine Kapsel ist kein Lebensmittel. Wir prüfen stattdessen, ob die <b>Dosis</b> innerhalb der EFSA-Grenzwerte liegt.</div>
      </div>
    </div>` : `
    <div class="scorebar">
      ${scoreLead(d, 96)}
      <div><div style="font-size:19px;font-weight:800;color:${farbeText(d.bewertung)}">${d.clean_score==null?"noch nicht bewertet":(d.score_vollstaendig?esc(d.bewertung||""):"Vorläufige Teilbewertung")}</div></div>
    </div>`}
    ${suppSummary}
    ${d.enthaelt_alkohol?`<div class="note" style="background:var(--k-fef2f2);border-color:var(--k-fca5a5);color:var(--k-b91c1c)">⚠️ <b>Enthält Alkohol (Ethanol)</b> – als krebserregend eingestuft (IARC Gruppe 1). Im Tropfen gering dosiert, für Schwangere, Kinder & Abstinente dennoch relevant.</div>`:""}
    ${_azoWarn?`<div class="note" style="background:var(--k-fef2f2);border-color:var(--k-fca5a5);color:var(--k-b91c1c)">⚠️ <b>Enthält synthetische Azo-Farbstoffe</b> – tragen den EU-Pflichthinweis „kann Aktivität und Aufmerksamkeit bei Kindern beeinträchtigen". Deckelt die Wertung auf höchstens „Gut".</div>`:""}
    ${_ksuessWarn?`<div class="note" style="background:var(--k-fffbeb);border-color:var(--k-fde68a);color:var(--k-92400e)">⚠️ <b>Enthält künstliche Süßstoffe</b> (z. B. Sucralose/Acesulfam) – kalorienarm, aber umstritten. Bei gesüßten Getränken deckelt es die Wertung auf höchstens „Mittel".</div>`:""}
    ${_istSupp?`<div id="riAmpel" data-pid="${esc(d.id)}"><div class="note" style="background:var(--k-f4f5f4);color:var(--muted)">Prüfe die Dosierung gegen die EFSA-Grenzwerte…</div></div>`:(!d.score_vollstaendig?`<div class="note teilhint">⚠️ Noch nicht voll bewertet (Zutatenqualität fehlt) – der Index kann sich ändern.</div>`:"")}
    ${!hasFeat('pk_naehrwerte') ? pkSperre('Nährwerte pro 100 g','Energie, Fett, Zucker, Ballaststoffe, Eiweiß, Salz')
       : (mRows?`<div style="font-size:11px;text-transform:uppercase;letter-spacing:.5px;color:var(--green);margin:18px 0 6px">Nährwerte pro 100 g</div>${mRows}`:"")}
    ${warumBlock}
    ${_sd ? zutatenBlock : ""}
    ${_sd ? naehrstoffHtml(d) : ""}
    ${bzBlock}
    ${_sd ? "" : upsellBlock}
  `;
  document.getElementById("overlay").classList.add("open");
  /* Die Reinheits-Ampel wird nachgeladen (RPC gegen die EFSA-Grenzwerte).
     Sie ersetzt bei Supplements den Platz, an dem sonst der Score steht. */
  if(typeof ladeReinheitsAmpel === "function") ladeReinheitsAmpel();
}
/* Ein gesperrter Block sagt, WAS fehlt und WARUM - er verschwindet nicht einfach.
   Ein Block, der spurlos fehlt, sieht aus wie ein Fehler; einer mit Schloss wie ein Angebot. */
function pkSperre(titel, was){
  var angemeldet = !!ME;
  var txt  = angemeldet ? 'Mit Premium freigeschaltet' : 'Mit kostenlosem Konto sichtbar';
  var knopf = angemeldet
    ? '<button onclick="closeP();navTo(\'premium\')" style="margin-top:9px;padding:9px 16px;border:0;border-radius:9px;background:var(--green);color:var(--auf-gruen);font-size:13.5px;font-weight:700;cursor:pointer">Premium ansehen</button>'
    : '<button onclick="closeP();openLogin()" style="margin-top:9px;padding:9px 16px;border:0;border-radius:9px;background:var(--green);color:var(--auf-gruen);font-size:13.5px;font-weight:700;cursor:pointer">Kostenlos anmelden</button>';
  return '<div style="margin:16px 0 4px;border:1px dashed var(--line);border-radius:14px;padding:15px 14px;text-align:center;background:var(--bg)">'
    +'<div style="font-size:11px;text-transform:uppercase;letter-spacing:.5px;color:var(--muted);margin-bottom:4px">'+esc(titel)+'</div>'
    +'<div style="font-size:13.5px;color:var(--ink);font-weight:600">'+esc(was)+'</div>'
    +'<div style="font-size:12.5px;color:var(--muted);margin-top:3px">'+txt+'</div>'
    + knopf
  +'</div>';
}
function closeP(){
  var ov=document.getElementById("overlay");
  if(ov){ ov.classList.remove("open");
    if(ov.classList.contains("fgEditorFull")){ ov.classList.remove("fgEditorFull");
      ov.style.background=""; ov.style.backdropFilter=""; ov.style.padding=""; ov.style.alignItems=""; ov.style.justifyContent=""; ov.style.left=""; } }
  var pn=document.getElementById("panel"); if(pn){ pn.style.maxWidth=""; pn.style.width=""; pn.style.height=""; pn.style.maxHeight=""; pn.style.borderRadius=""; }
  try{ var _nf=document.getElementById("navFreigabe"); if(_nf) _nf.style.display="none"; }catch(e){}
  try{ feFreigabeLeisteHide(); }catch(e){}
}
/* Eine Karte beginnt oben. Immer. (Ralph, 18.07.2026)
   Wer eine Produktkarte weit unten schliesst und wieder oeffnet, landete bisher
   mitten im Blutzucker-Verlauf - das Panel behaelt seine Scroll-Position, weil es
   dasselbe DOM-Element bleibt und nur neu befuellt wird.
   An 5 der 11 Oeffnen-Stellen stand das Zuruecksetzen schon, an 6 fehlte es.
   Statt sechs Einzelflicken wird hier EINMAL beobachtet, wann das Overlay aufgeht -
   das faengt auch jeden kuenftigen Oeffnen-Weg ab, an den sonst niemand denkt. */
(function panelImmerObenBeginnen(){
  function start(){
    var ov=document.getElementById("overlay"); if(!ov) return;
    try{
      new MutationObserver(function(){
        if(ov.classList.contains("open")){
          var p=document.getElementById("panel");
          if(p) p.scrollTop=0;
        }
      }).observe(ov,{attributes:true, attributeFilter:["class"]});
    }catch(e){}
  }
  if(document.readyState==="loading") document.addEventListener("DOMContentLoaded",start);
  else start();
})();
function esc(s){return (s==null?"":String(s)).replace(/[&<>"]/g,m=>({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;"}[m]));}
function naehrstoffHtml(d){
  const ns=d&&d.naehrstoffe; if(!ns||!ns.length) return '';
  const rows=ns.map(x=>{
    const menge=(x.menge!=null?(String(x.menge).replace(/\.0+$/,'').replace('.',',')+' '+esc(x.einheit||'')):'');
    let right;
    if(x.nrv!=null){ const pct=Math.round(x.nrv); const w=Math.max(4,Math.min(100,pct)); const lbl=(pct>1000?'&gt;1000':pct)+'%';
      right='<div style="flex:0 0 118px;display:flex;align-items:center;gap:7px;justify-content:flex-end"><div style="flex:1;height:6px;background:var(--line);border-radius:4px;overflow:hidden"><div style="width:'+w+'%;height:100%;background:var(--green)"></div></div><span style="font-weight:700;color:var(--greendk);min-width:52px;text-align:right">'+lbl+'</span></div>';
    } else { right='<span style="flex:0 0 118px;text-align:right;font-size:11px;color:var(--muted);line-height:1.2">kein offizieller<br>Tagesbedarf</span>'; }
    return '<div style="display:flex;align-items:center;gap:14px;padding:9px 2px;border-top:1px solid var(--line)">'
      +'<span style="flex:1 1 auto;min-width:0;font-size:13px">'+esc(x.n)+'</span>'
      +'<span style="flex:0 0 auto;font-size:12.5px;color:var(--muted);white-space:nowrap;text-align:right;min-width:56px">'+menge+'</span>'
      +right+'</div>';
  }).join('');
  return '<div style="background:var(--card);border:1px solid var(--line);border-radius:12px;padding:12px 14px;margin:12px 0">'
    +'<div style="font-weight:600;font-size:13.5px">🎯 Deckt deinen Tagesbedarf</div>'
    +'<div style="font-size:11px;color:var(--muted);margin:2px 0 2px">pro Tagesportion · % der Referenzmenge (NRV, EU)</div>'
    +rows+'</div>';
}
function infoPop(title, html){
  let ov=document.getElementById("infoPopOverlay");
  if(ov) ov.remove();
  ov=document.createElement("div"); ov.id="infoPopOverlay";
  ov.style.cssText="position:fixed;inset:0;background:rgba(0,0,0,.45);display:flex;align-items:center;justify-content:center;z-index:60;padding:16px";
  ov.onclick=e=>{ if(e.target===ov) ov.remove(); };
  ov.innerHTML=`<div style="background:var(--card);border-radius:14px;max-width:460px;width:100%;max-height:82vh;overflow:auto;padding:18px;box-shadow:0 12px 44px rgba(0,0,0,.25)">
    <div style="display:flex;justify-content:space-between;align-items:center;gap:8px;margin-bottom:8px"><h3 style="margin:0;font-size:17px">${title}</h3><button onclick="document.getElementById('infoPopOverlay').remove()" style="border:0;background:var(--bg);border-radius:8px;padding:6px 10px;cursor:pointer;font-size:14px">✕</button></div>
    <div style="font-size:14px;line-height:1.55;color:var(--ink)">${html}</div></div>`;
  document.body.appendChild(ov);
}
function fettInfo(){
  infoPop("Fett & Kohlenhydrate – worauf beruht das?", `
    <p style="margin:.2em 0">Die Prozentzahl ist der <b>Anteil der Tagesenergie aus Fett</b>. Grundlage sind offizielle Richtwerte:</p>
    <ul style="margin:.2em 0 .4em;padding-left:18px">
      <li><b>Fett – DGE / D-A-CH-Richtwert:</b> rund <b>30 %</b> der Energie für Erwachsene.</li>
      <li>International (AMDR): <b>20–35 %</b> akzeptabel – Richtung 35 % v. a. bei körperlich Aktiven / Low-Carb-nah.</li>
    </ul>
    <p style="margin:.2em 0"><b>Kohlenhydrate – DGE-Richtwert: &gt; 50 %</b> der Energie (Mischkost). Im Rechner sind KH bewusst der <b>Rest</b> nach Eiweiß und Fett – das entspricht der DGE-Logik (KH ergeben sich aus Energiebedarf, Eiweiß- und Fett-Richtwert). Bei viel Eiweiß/mehr Fett können KH etwas unter 50 % landen – für Fitness-/Abnehmziele in Ordnung.</p>
    <p style="margin:.2em 0">Deshalb die Fett-Auswahl <b>25 / 30 / 35 %</b>; <b>30 %</b> ist Standard. Eiweiß wird separat aus g/kg gerechnet.</p>
    <p style="margin:.6em 0 0;color:var(--muted);font-size:13px">Wichtiger als die exakte Zahl ist die <b>Qualität</b>: ungesättigte Fette (Nüsse, Öle, Fisch) und komplexe/ballaststoffreiche KH (Vollkorn, Gemüse) bevorzugen. Quelle: DGE-Referenzwerte.</p>`);
}
function eiweissInfo(){
  infoPop("Eiweißbedarf – wie berechnen?", `
    <p style="margin:.2em 0"><b>Wie viel?</b> Richtwert <b>1,5–2 g Eiweiß pro kg</b> – je aktiver bzw. muskelaufbauender, desto eher Richtung 2 g.</p>
    <p style="margin:.6em 0 .2em"><b>Auf welches Gewicht beziehen?</b> Eiweiß baut/erhält Muskeln, nicht Fettgewebe – deshalb kommt es auf den Körperfettanteil an:</p>
    <ul style="margin:.2em 0 .4em;padding-left:18px">
      <li><b>Normalgewicht:</b> aktuelles Gewicht passt gut.</li>
      <li><b>Übergewicht:</b> aktuelles Gewicht <u>überschätzt</u> den Bedarf → besser das <b>Zielgewicht</b> nehmen.</li>
      <li><b>Am genauesten:</b> die fettfreie Masse = Gewicht × (1 − Körperfett%), falls bekannt.</li>
    </ul>
    <p style="margin:.2em 0;color:var(--muted);font-size:13px">Faustregel: Willst du abnehmen (Ziel &lt; aktuell), rechne mit dem Zielgewicht; beim Halten/Aufbauen mit dem aktuellen Gewicht.</p>
    <p style="margin:.7em 0 0;background:var(--k-fef2f2);border:1px solid var(--k-fecaca);border-radius:8px;padding:9px;color:var(--k-991b1b)"><b>⚠️ Bei Nierenleiden:</b> Eiweiß <b>nicht</b> erhöhen – eine eingeschränkte Nierenfunktion kann durch hohe Eiweißmengen belastet werden. Vorher ärztlich abklären. Die Option „Nierenleiden berücksichtigen" begrenzt den Wert automatisch.</p>`);
}
