let REZEPTE=null;
/* Admin-Bereiche laufen im Dunkelmodus (Ralph, 18.07.2026) - unabhaengig davon,
   was der Theme-Schalter fuer die Nutzeransicht sagt. Grund: Der Admin ist ein
   Arbeitsplatz, die Nutzeransicht ein Schaufenster. Wer beides gleich einfaerbt,
   sieht nicht mehr, wo er gerade steht.
   Die persoenliche Wahl (auto/hell/dunkel) bleibt unangetastet - beim Verlassen
   des Admin-Bereichs wird sie einfach wieder angewendet. */
var ADMIN_MODI = ["freigabe","stufen","nutzer","rikiimport"];
function adminThemeAnwenden(m){
  try{
    var istAdmin = ADMIN_MODI.indexOf(m) >= 0;
    if(istAdmin){ document.documentElement.setAttribute("data-theme","dark"); }
    else if(typeof window.riThemeAnwenden === "function"){
      window.riThemeAnwenden(window.riThemeWahl || "auto");
    }
  }catch(e){}
}
function setMode(m){
  window._curMode=m;
  adminThemeAnwenden(m);
  try{ window.scrollTo(0,0); }catch(e){}
  document.getElementById("tabProd").classList.toggle("active",m==="produkte");
  document.getElementById("tabRez").classList.toggle("active",m==="rezepte");
  document.getElementById("tabVor").classList.toggle("active",m==="vorschlagen");
  document.getElementById("tabTb").classList.toggle("active",m==="tagebuch");
  document.getElementById("tabPlan").classList.toggle("active",m==="planer");
  document.getElementById("tabTrain").classList.toggle("active",m==="training");
  document.getElementById("tabProfil").classList.toggle("active",m==="profil");
  document.getElementById("tabFg").classList.toggle("active",m==="freigabe");
  document.getElementById("tabStufen").classList.toggle("active",m==="stufen");
  document.getElementById("tabUsers").classList.toggle("active",m==="nutzer");
  document.getElementById("startView").style.display = m==="start"?"":"none";
  document.getElementById("prodView").style.display = m==="produkte"?"":"none";
  document.getElementById("rezeptView").style.display = m==="rezepte"?"":"none";
  document.getElementById("vorschlagView").style.display = m==="vorschlagen"?"":"none";
  document.getElementById("tagebuchView").style.display = m==="tagebuch"?"":"none";
  document.getElementById("planerView").style.display = m==="planer"?"":"none";
  document.getElementById("trainingView").style.display = m==="training"?"":"none";
  document.getElementById("zyklusView").style.display = m==="zyklus"?"":"none";
  document.getElementById("darmView").style.display = m==="darm"?"":"none";
  document.getElementById("einkaufView").style.display = m==="einkauf"?"":"none";
  if(m==="einkauf") renderEinkaufSeite();
  document.getElementById("profilView").style.display = m==="profil"?"":"none";
  document.getElementById("freigabeView").style.display = m==="freigabe"?"":"none";
  document.getElementById("stufenView").style.display = m==="stufen"?"":"none";
  document.getElementById("usersView").style.display = m==="nutzer"?"":"none";
  { var _rv=document.getElementById("rikiView"); if(_rv) _rv.style.display = m==="rikiimport"?"":"none"; }
  if(m==="produkte"){ try{ render(); }catch(e){} }
  if(m==="rezepte") loadRezepte();
  if(m==="tagebuch"){ const _d=document.getElementById("tbDatum"); if(_d) _d.value=tbToday(); loadTagebuch(); }
  if(m==="planer") loadPlaner();
  if(m==="profil") loadProfil();
  if(m==="training") loadTraining();
  if(m==="zyklus") renderZyklus();
  if(m==="darm") renderDarm();
  if(m==="freigabe"){ if(!(ME&&ME.is_admin)){ setMode("produkte"); return; } loadFreigabe(); fgTab((window._fgTab&&window._fgTab!=='produkte'&&window._fgTab!=='kontakt')?window._fgTab:'zuverif'); }
  if(m==="stufen"){ if(!(ME&&ME.is_admin)){ setMode("produkte"); return; } loadStufen(); }
  if(m==="nutzer"){ if(!(ME&&ME.is_admin)){ setMode("produkte"); return; } loadUsers(); }
  if(m==="rikiimport"){ if(!(ME&&ME.is_admin)){ setMode("produkte"); return; } rkInit(); }
  if(m==="vorschlagen"){ updateGate(); renderVorShots(); }
  if(m!=="vorschlagen") stopScan();
  if(m==="start") renderStart();
  bnActive(m);
  if(typeof updateFloatBtns==='function') updateFloatBtns();
}
