    if(!list.length) return '';
    const rangbar=bundleRangbar(list);
    if(rangbar){ list.sort((a,b)=>num(b.clean_score)-num(a.clean_score)); list=list.slice(0,2); }
    const cards=list.map((p,i)=>bundleCard(p,rangbar&&list.length>1&&i===0)).join('');
    return '<div class="zbCat" style="margin-top:13px">'
