async function renderSchritte(){
  const box=document.getElementById("schritteBox"); if(!box) return;
  if(!window._schrDate) window._schrDate=tbToday();
  const sel=window._schrDate, today=tbToday();
  let tag=0, verlauf=[];
  try{ const r=await client.rpc("cb_schritte_tag",{p_datum:sel}); tag=Number(r.data)||0; }catch(e){}
  try{ const r=await client.rpc("cb_schritte_verlauf",{p_bis:today,p_tage:7}); verlauf=r.data||[]; }catch(e){}
  /* Bento-Stil wie die Kacheln daueber: dunkel, Glow, eigene Farbe.
     Diese Kacheln kennen KEINEN Hell/Dunkel-Modus - sie sind immer dunkel,
     genau wie die Startseiten-Kacheln. Deshalb feste Farben, keine Token. */
  const card='position:relative;overflow:hidden;background:radial-gradient(120% 120% at 18% 10%,#1f5e39,#0c1a12 66%);border:0;border-radius:16px;padding:14px 15px;margin-bottom:12px;box-shadow:0 8px 22px rgba(15,40,25,.26)';
  const ZIEL=10000, wd=["So","Mo","Di","Mi","Do","Fr","Sa"];
  const vals=verlauf.map(x=>Number(x.schritte)||0);
  const tage=vals.length||1, sum=vals.reduce((a,b)=>a+b,0), avg=Math.round(sum/tage);
  const maxV=Math.max(ZIEL, ...vals, 1);
  const bars=verlauf.map(x=>{
    const v=Number(x.schritte)||0, dd=new Date(x.datum+"T00:00:00");
    const h=Math.round(4+(v/maxV)*34), isSel=x.datum===sel;
    const col=v>=ZIEL?"var(--k-16a34a)":(v>0?"var(--k-65a30d)":"var(--k-e5e9e6)");
    return '<button onclick="schrPickDate(\''+x.datum+'\')" title="'+dd.toLocaleDateString('de-DE')+': '+v.toLocaleString('de-DE')+'" style="flex:1;display:flex;flex-direction:column;align-items:center;gap:3px;background:none;border:0;cursor:pointer;padding:0">'
      +'<div style="height:40px;display:flex;align-items:flex-end;width:100%;justify-content:center"><div style="width:66%;height:'+h+'px;background:'+col+';border-radius:5px 5px 2px 2px;'+(isSel?'outline:2px solid var(--k-14532d);outline-offset:1px':'')+'"></div></div>'
      +'<div style="font-size:10px;color:'+(isSel?'var(--k-14532d)':'var(--k-94a3b8)')+';font-weight:'+(isSel?'700':'500')+'">'+wd[dd.getDay()]+'</div></button>';
  }).join("");
  const selD=new Date(sel+"T00:00:00");
  const selLbl=selD.toLocaleDateString("de-DE",{weekday:"short",day:"numeric",month:"short"})+(sel===today?" · heute":"");
  const nextOff = sel>=today;
  const open = window._schrOpen ? '' : 'none';
  box.innerHTML='<div style="'+card+'">'
    +'<div style="position:relative;z-index:2;display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><div style="font-weight:700;font-size:14px;color:#fff;display:flex;align-items:center;gap:6px">'+riIco('shoe',18)+' Schritte</div><span style="font-size:12.5px;color:rgba(255,255,255,.55)">heute <b style="color:#fff">'+(tag?tag.toLocaleString("de-DE"):"–")+'</b>'+(tag?' · <span style="color:#5ef2a0;font-weight:700">'+Math.min(100,Math.round(tag/ZIEL*100))+'%</span>':'')+'</span></div>'
    +'<div style="position:relative;z-index:2;display:flex;gap:8px;align-items:center"><input id="startSchritte" type="number" min="0" value="'+(tag||"")+'" placeholder="z. B. 8000" style="flex:1;min-width:0;padding:10px;border:1px solid rgba(255,255,255,.20);border-radius:10px;font-size:14px;background:rgba(255,255,255,.08);color:#fff">'
      +'<button onclick="saveSchritte()" style="padding:10px 15px;border:0;border-radius:10px;background:#5ef2a0;color:#0c1a12;font-weight:700;cursor:pointer;font-size:13px">Speichern</button></div>'
    +'<div style="position:relative;z-index:2;height:7px;border-radius:99px;background:rgba(255,255,255,.12);overflow:hidden;margin-top:10px"><div style="height:100%;width:'+Math.min(100,Math.round((tag/ZIEL)*100))+'%;background:'+(tag>=ZIEL?'#7cff9b':'#5ef2a0')+';border-radius:99px;transition:width .6s cubic-bezier(.22,1,.36,1)"></div></div>'
    +'<div id="startSchritteMsg" style="position:relative;z-index:2;font-size:12px;color:rgba(255,255,255,.6);margin-top:5px;min-height:15px"></div>'
    +'<button onclick="schrToggleChart()" style="position:relative;z-index:2;width:100%;text-align:left;background:none;border:0;padding:2px 0 0;cursor:pointer;color:#5ef2a0;font-size:12.5px;font-weight:600">📊 7-Tage-Verlauf · Ø '+avg.toLocaleString("de-DE")+'/Tag <span id="schrArrow">'+(window._schrOpen?'▲':'▼')+'</span></button>'
    +'<div id="schrChart" style="display:'+open+';margin-top:8px">'
      +'<div style="display:flex;align-items:center;gap:6px;margin-bottom:6px">'
        +'<button onclick="schrShiftDay(-1)" title="Tag zurück" style="padding:5px 9px;border:1px solid var(--line);border-radius:8px;background:var(--card);cursor:pointer">‹</button>'
        +'<span style="flex:1;text-align:center;font-size:12.5px;color:var(--ink);font-weight:600">'+selLbl+' · Ziel '+ZIEL.toLocaleString("de-DE")+'</span>'
        +'<button onclick="schrShiftDay(1)" '+(nextOff?'disabled':'')+' title="Tag vor" style="padding:5px 9px;border:1px solid var(--line);border-radius:8px;background:var(--card);cursor:'+(nextOff?'not-allowed':'pointer')+';opacity:'+(nextOff?'.4':'1')+'">›</button></div>'
      +'<div style="display:flex;gap:4px;align-items:flex-end">'+bars+'</div>'
    +'</div>'
    +'</div>';
}
function schrToggleChart(){ window._schrOpen=!window._schrOpen; var c=document.getElementById('schrChart'); var a=document.getElementById('schrArrow'); if(c) c.style.display=window._schrOpen?'':'none'; if(a) a.textContent=window._schrOpen?'▲':'▼'; }
function schrPickDate(ds){ window._schrDate=ds; window._schrOpen=true; renderSchritte(); }
function schrShiftDay(n){
  const cur=window._schrDate||tbToday(); const d=new Date(cur+"T00:00:00"); d.setDate(d.getDate()+n);
  const iso=tbISO(d); if(iso>tbToday()) return; window._schrDate=iso; window._schrOpen=true; renderSchritte();
}
async function saveSchritte(){
  const el=document.getElementById("startSchritte"); if(!el) return;
  const v=Math.max(0,parseInt(el.value)||0), datum=window._schrDate||tbToday();
  const {error}=await client.rpc("cb_schritte_speichern",{p_datum:datum, p_schritte:v});
  await renderSchritte();
  const m=document.getElementById("startSchritteMsg");
  if(m){ if(error){ m.style.color="var(--k-dc2626)"; m.textContent="Fehler: "+error.message; } else { m.style.color="var(--k-16a34a)"; m.textContent="✓ "+v.toLocaleString("de-DE")+" gespeichert"; } }
}
