async function planSave(){
  if(!_planTarget) return; const msg=document.getElementById("planPickMsg"); msg.style.color="var(--k-dc2626)";
  const rezId=document.getElementById("planRez").value;
  const prodV=(document.getElementById("planProd").value||"").trim();
  const menge=parseFloat(document.getElementById("planMenge").value)||null;
  let typ,rez=null,prod=null,titel=null;
  if(rezId){ typ='rezept'; rez=rezId; const r=(REZEPTE||[]).find(x=>x.id===rezId); titel=r?r.name:null; }
  else if(prodV){ const p=(ALL||[]).find(x=>prodLabel(x).toLowerCase()===prodV.toLowerCase())||(ALL||[]).find(x=>(x.name||"").toLowerCase()===prodV.toLowerCase()); if(!p){ msg.textContent="Produkt nicht gefunden – aus der Liste wählen."; return; } typ='produkt'; prod=p.id; titel=p.name; }
  else { msg.textContent="Rezept oder Produkt wählen."; return; }
  const {error}=await client.rpc("cb_plan_add",{p_datum:_planTarget.ds,p_slot:_planTarget.slot,p_typ:typ,p_rezept:rez,p_produkt:prod,p_menge:menge,p_titel:titel});
  if(error){ msg.textContent="Fehler: "+error.message; return; }
  document.getElementById("planPick").style.display="none"; renderPlaner();
}
async function planDel(id){ await client.rpc("cb_plan_del",{p_eintrag:id}); renderPlaner(); }
async function planToTb(id,quiet){
  const it=(_planCache||[]).find(e=>e.eintrag_id===id); if(!it) return;
  try{
    if(it.typ==='rezept' && it.rezept_id){ await client.rpc("cb_tb_rezept",{p_mahlzeit:it.slot,p_rezept:it.rezept_id,p_datum:it.datum}); }
    else if(it.produkt_id){ const p=(ALL||[]).find(x=>x.id===it.produkt_id); const g=it.menge_g||(p?tbDefaultPortion(p):100); await client.rpc("cb_tb_eintragen",{p_mahlzeit:it.slot,p_produkt:it.produkt_id,p_menge_g:g,p_datum:it.datum}); }
    else { if(!quiet) alert("Nur Rezepte/Produkte können übernommen werden."); return; }
    if(!quiet) alert("✓ ins Tagebuch übernommen ("+it.datum+")");
  }catch(e){ if(!quiet) alert("Fehler: "+e.message); }
}
async function planDayToTb(ds){
  const items=(_planCache||[]).filter(e=>e.datum===ds); if(!items.length) return;
  if(!confirm("Alle "+items.length+" Einträge dieses Tages ins Tagebuch übernehmen?")) return;
  for(const it of items){ await planToTb(it.eintrag_id,true); }
  alert("✓ "+items.length+" Einträge ins Tagebuch übernommen.");
}
/* Einkaufsliste als eigene Seite (Menü + Startseite). Der Button im Tagebuch bleibt zusätzlich. */
