function tbmCalc(){
  const el=document.getElementById("tbmVorschau"); if(!el) return;
  const g=parseFloat((document.getElementById("tbmMenge")||{}).value)||0;
  if(g<=0){ el.textContent="Menge in g eingeben → wird automatisch umgerechnet."; return; }
  const per=id=>{const v=parseFloat((document.getElementById(id)||{}).value); return isNaN(v)?0:v;};
  const f=g/100, r=x=>Math.round(x*10)/10;
  el.textContent="≈ "+Math.round(per("tbmKcal")*f)+" kcal für "+g+" g · EW "+r(per("tbmEiw")*f)+" g · KH "+r(per("tbmKh")*f)+" g · Fett "+r(per("tbmFett")*f)+" g";
}
async function tbAddManualSave(){
  const name=(document.getElementById("tbmName").value||"").trim();
  const m=document.getElementById("tbAddMsg");
  if(!name){ if(m){m.style.color="var(--k-f87171)";m.textContent="Name angeben.";} return; }
  const menge=parseFloat(document.getElementById("tbmMenge").value)||0;
  if(menge<=0){ if(m){m.style.color="var(--k-f87171)";m.textContent="Menge in g angeben.";} return; }
  const f=menge/100, per=id=>{const v=parseFloat(document.getElementById(id).value); return isNaN(v)?null:v;};
  const p100={k:per("tbmKcal"),e:per("tbmEiw"),c:per("tbmKh"),ff:per("tbmFett")};
  const kcal=p100.k==null?null:Math.round(p100.k*f),
    eiw=p100.e==null?null:Math.round(p100.e*f*10)/10,
    kh=p100.c==null?null:Math.round(p100.c*f*10)/10,
    fett=p100.ff==null?null:Math.round(p100.ff*f*10)/10;
  const meal=window._tbAddMeal||"Frühstück", datum=document.getElementById("tbDatum").value||tbToday();
  const {error}=await client.rpc("cb_tb_manuell",{p_mahlzeit:meal,p_name:name,p_menge_g:menge,p_kcal:kcal,p_protein:eiw,p_kh:kh,p_fett:fett,p_datum:datum});
  if(error){ if(m){m.style.color="var(--k-f87171)";m.textContent="Fehler: "+error.message;} return; }
  const ov=document.getElementById("tbAddOv"); if(ov) ov.remove(); loadTagebuch();
}
// EN-13: Open Food Facts als Vorschlag-Quelle. Läuft im Browser (Sandbox hat keinen Netz-Zugang).
// Befüllt nur das Formular; nichts geht ungeprüft live – Speichern landet wie gehabt in der Admin-Queue.
async function offLookup(){
  const msg=document.getElementById("tbmOffMsg");
  const ean=(document.getElementById("tbmEan")||{}).value||"";
  const code=ean.replace(/\D/g,"");
  if(code.length<8){ if(msg){ msg.style.color="var(--k-e8920c)"; msg.textContent="Bitte gültigen Barcode (EAN) eingeben."; } return; }
  if(msg){ msg.style.color="var(--k-6b6256)"; msg.textContent="Suche bei Open Food Facts…"; }
  try{
    const url="https://world.openfoodfacts.org/api/v2/product/"+encodeURIComponent(code)+".json?fields=product_name,product_name_de,brands,nutriments";
    const r=await fetch(url,{headers:{"Accept":"application/json"}});
    const j=await r.json();
    if(!j || j.status!==1 || !j.product){
      /* Kein OFF-Treffer = Sackgasse. Hier MUSS der Weg über das Etikettfoto angeboten werden. */
      if(msg){ msg.style.color="var(--k-e8920c)";
        msg.innerHTML="Kein Treffer bei Open Food Facts für "+esc(code)+".<br>"
          +"<span style=\"color:var(--k-6b6256)\">Du hast das Produkt in der Hand? Fotografiere Zutaten &amp; Nährwerte – dann nehmen wir es auf:</span><br>"
          +etikettCtaBtn(code); }
      return;
    }
    const p=j.product, n=p.nutriments||{};
    const nm=(p.product_name_de||p.product_name||"").trim();
    const marke=(p.brands||"").split(",")[0].trim();
    const setV=(id,v)=>{ const el=document.getElementById(id); if(el&&v!=null&&!isNaN(v)) el.value=Math.round(v*10)/10; };
    if(nm){ const e=document.getElementById("tbmName"); if(e) e.value = marke? (nm+" ("+marke+")") : nm; }
    setV("tbmKcal", n["energy-kcal_100g"]);
    setV("tbmEiw",  n["proteins_100g"]);
    setV("tbmKh",   n["carbohydrates_100g"]);
    setV("tbmFett", n["fat_100g"]);
    /* Den OFF-Treffer an die Scan-Warteschlange hängen: Dieses Produkt fehlt im Katalog,
       ein Nutzer hat es gerade gegessen UND es ist bei OFF vorhanden → bester Kandidat.
       Ohne das ging die Information nach dem Tagebuch-Eintrag verloren. */
    try{ await client.rpc("cb_scan_off_treffer",{
      p_ean:code, p_name:nm||null, p_marke:marke||null,
      p_kcal:n["energy-kcal_100g"]??null, p_protein:n["proteins_100g"]??null,
      p_kh:n["carbohydrates_100g"]??null, p_fett:n["fat_100g"]??null
    }); }catch(e){}
    if(msg){ msg.style.color="var(--k-2e7d32)"; msg.innerHTML="✓ Werte übernommen (je 100 g). <b>Bitte prüfen</b> – Open-Food-Facts-Daten sind community-gepflegt. Menge in g ergänzen, dann Eintragen. <span style=\"color:var(--k-6b6256)\">Das Produkt ist für den Katalog vorgemerkt – danke!</span>"; }
  }catch(e){
    if(msg){ msg.style.color="var(--k-f87171)"; msg.textContent="Abruf fehlgeschlagen (Netz/CORS): "+e.message; }
  }
}
