async function editMenge(id,cur,pid){
  const sg=stkOf(pid);
  if(sg){
    const n=prompt("Neue Anzahl (Stück):", Math.round(cur/sg));
    if(n===null) return;
    const v=parseFloat(String(n).replace(",",".")); if(!v||v<=0) return;
    await client.rpc("cb_tb_menge",{p_eintrag:id,p_menge_g:Math.round(v*sg)});
    loadTagebuch(); return;
  }
  const n=prompt("Neue Menge in Gramm:", cur);
  if(n===null) return;
  const v=parseFloat(String(n).replace(",",".")); if(!v||v<=0) return;
  await client.rpc("cb_tb_menge",{p_eintrag:id,p_menge_g:v});
  loadTagebuch();
}
