/* Beleg-Feld: JEDE Quelle wird angehaengt, keine ueberschreibt eine andere.
   Fehler bis 18.07.2026: alle drei Kaskaden schrieben nur mit `if(!bl.value)`.
   Wer erst OFF und dann USDA holte, hatte am Ende `Quelle_Typ = USDA`, aber im Beleg
   stand weiterhin nur OFF - die Kombination war nicht bloss unvollstaendig, sondern FALSCH.
   §4.3 verlangt, dass die Quelle festgehalten wird; eine verschwiegene zweite Quelle
   ist genau das Gegenteil. */
function feBelegAdd(text){
  var bl=document.getElementById("fe_beleg"); if(!bl||!text) return;
  var cur=(bl.value||"").trim();
  if(cur.indexOf(text)>=0) return;          /* schon vermerkt - nicht doppeln */
  bl.value = cur ? (cur+" · "+text) : text;
}
