    return '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">'
      +'<div style="flex:1;font-size:14px;color:'+(has?'var(--k-166534)':'var(--k-374151)')+'">'+(has?'✓ ':'')+label+'</div>'
      +(has
        ? '<button onclick="vorShotDel(\''+k+'\')" style="padding:7px 10px;border:1px solid var(--line);border-radius:8px;background:var(--card);color:var(--k-b91c1c);font-size:13px;cursor:pointer">Entfernen</button>'
        : '<button onclick="vorShotCam(\''+k+'\')" style="padding:7px 10px;border:1px solid var(--k-16a34a);border-radius:8px;background:var(--greenlt,var(--k-ecfdf5));color:var(--greendk,var(--k-166534));font-size:13px;cursor:pointer">📷 Kamera</button>'
         +'<button onclick="vorPickFile(\''+k+'\')" style="padding:7px 10px;border:1px dashed var(--k-16a34a);border-radius:8px;background:var(--card);color:var(--greendk,var(--k-166534));font-size:13px;cursor:pointer">📁 Datei</button>')
      +'</div>';
