/* ===== Wächter-Übersicht (Portal-M-Umbau, Ralph 24.07.2026) =====
   Der 🛡️-Bereichsknopf öffnet den täglichen TÜV: 10 harte Gates (müssen 0 sein) + offene Hinweise.
   Zahlen live aus cb_admin_waechter. */
async function waechterOpen(){
  if(!(ME&&ME.is_admin)) return;
  var ov=document.getElementById("waechterOv");
  if(!ov){ ov=document.createElement("div"); ov.id="waechterOv";
    ov.style.cssText="position:fixed;inset:0;z-index:9998;display:flex;align-items:flex-start;justify-content:center;background:rgba(20,32,48,.45);overflow:auto;padding:24px 12px";
    document.body.appendChild(ov); }
  ov.style.display="flex";
  ov.innerHTML='<div style="background:var(--card,#fff);color:var(--ink);border-radius:16px;max-width:840px;width:100%;box-shadow:0 20px 60px rgba(20,40,70,.32);padding:20px;margin:auto">'
    +'<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;margin-bottom:4px"><div style="font-weight:800;font-size:18px">🛡️ Wächter – täglicher TÜV über den Katalog</div><button onclick="waechterClose()" style="border:0;background:var(--bg,#eef2f5);border-radius:8px;width:30px;height:30px;cursor:pointer;font-size:16px">✕</button></div>'
    +'<div style="font-size:12.5px;color:var(--muted);margin-bottom:10px">Harte Gates müssen 0 sein, sonst kein Livegang. Hinweise melden nur.</div>'
    +'<div id="waechterBody" style="font-size:13px;color:var(--muted)">Lade …</div>'
  +'</div>';
  try{
    var r=await client.rpc("cb_admin_waechter");
    if(r.error) throw new Error(r.error.message);
    var d=r&&r.data; if(typeof d==="string"){ try{ d=JSON.parse(d); }catch(_){} }
    waechterRender(d||{});
  }catch(e){ var b=document.getElementById("waechterBody"); if(b){ b.style.color="var(--k-dc2626)"; b.textContent="Konnte die Wächter nicht laden: "+(e&&e.message?e.message:e); } }
}
function waechterRender(d){
  var b=document.getElementById("waechterBody"); if(!b) return;
  var gates=(d&&d.gates)||[], hin=(d&&d.hinweise)||[];
  var offen=0; gates.forEach(function(g){ offen+=(+g.n||0); });
  var gruen=(offen===0);
  function tile(x,warn){
    var n=+x.n||0;
    var col=n===0?'var(--k-166534)':(warn?'var(--k-b45309)':'var(--k-dc2626)');
    var bg=n===0?'#eef8f1':(warn?'#fdf4e8':'#fcefee');
    return '<div style="border:1px solid var(--line);border-radius:11px;padding:11px;background:'+bg+'">'
      +'<div style="font-size:22px;font-weight:800;color:'+col+';line-height:1">'+n+'</div>'
      +'<div style="font-size:11.5px;font-weight:700;margin-top:5px;color:var(--ink)">'+esc(x.t)+'</div>'
      +(x.d?'<div style="font-size:10.5px;color:var(--muted);margin-top:3px">'+esc(x.d)+'</div>':'')
    +'</div>';
  }
  var grid='display:grid;grid-template-columns:repeat(auto-fill,minmax(148px,1fr));gap:9px';
  var h='<div style="display:flex;align-items:center;gap:12px;border-radius:12px;padding:12px 14px;margin-bottom:14px;background:'+(gruen?'#eef8f1':'#fcefee')+';border:1px solid '+(gruen?'#cfe8d8':'#f2ccc8')+'">'
    +'<div style="width:22px;height:22px;border-radius:50%;flex:0 0 auto;background:'+(gruen?'var(--k-16a34a)':'var(--k-dc2626)')+'"></div>'
    +'<div><b style="font-size:14px;color:'+(gruen?'#1e6b42':'#8a2019')+'">Go-Live-Gate: '+(gruen?'GRÜN':'ROT')+'</b>'
    +'<div style="font-size:12px;color:var(--muted);margin-top:2px">'+(gruen?'Alle harten Prüfungen auf 0 – der Katalog ist freigabefähig.':(offen+' harte Prüfung(en) offen – bitte beheben.'))+'</div></div></div>';
  h+='<div style="font-size:11.5px;font-weight:800;color:var(--muted);text-transform:uppercase;letter-spacing:.5px;margin:2px 0 8px">Harte Gates · müssen 0 sein</div>';
  h+='<div style="'+grid+'">'+gates.map(function(g){return tile(g,false);}).join("")+'</div>';
  h+='<div style="font-size:11.5px;font-weight:800;color:var(--muted);text-transform:uppercase;letter-spacing:.5px;margin:16px 0 8px">Offene Hinweise · melden nur</div>';
  h+='<div style="'+grid+'">'+hin.map(function(g){return tile(g,true);}).join("")+'</div>';
  b.style.color="var(--ink)"; b.innerHTML=h;
}
function waechterClose(){ var ov=document.getElementById("waechterOv"); if(ov) ov.style.display="none"; }
if(typeof window!=='undefined'){ window.waechterOpen=waechterOpen; window.waechterClose=waechterClose; }
async function rezVorschlagRun(){
  var zutRaw=((document.getElementById("rezVorZut")||{}).value||"");
  var zutaten=zutRaw.split(/[\n,;]+/).map(function(s){return s.trim();}).filter(function(s){return s.length>0;});
  var msg=document.getElementById("rezVorMsg"), list=document.getElementById("rezVorList"), btn=document.getElementById("rezVorBtn");
  if(list) list.innerHTML="";
  if(zutaten.length<2){ if(msg){ msg.style.color="var(--k-dc2626)"; msg.textContent="Bitte mindestens 2 Zutaten eingeben."; } return; }
  var kcal=parseFloat((document.getElementById("rezVorKcal")||{}).value)||null;
  var mz=((document.getElementById("rezVorMz")||{}).value||"")||null;
  if(btn){ btn.disabled=true; btn.textContent="Riki denkt nach …"; }
  if(msg){ msg.style.color="var(--muted)"; msg.textContent="🤖 Riki sucht passende Gerichte …"; }
  try{
    var s=await client.auth.getSession(); var tok=(s&&s.data&&s.data.session)?s.data.session.access_token:client.supabaseKey;
    var r=await fetch(client.supabaseUrl+"/functions/v1/riki-rezept-vorschlag",{method:"POST",
      headers:{"Content-Type":"application/json","Authorization":"Bearer "+tok,"apikey":client.supabaseKey},
      body:JSON.stringify({zutaten:zutaten, kcal_tag:kcal, mahlzeit:mz, anzahl:3})});
    var d=await r.json();
    if(!r.ok||d.error){ throw new Error(d.error||("Fehler "+r.status)); }
    window._rezVorschlaege=d.vorschlaege||[];
    rezVorschlagRender(d);
    if(msg){ msg.style.color="var(--muted)"; msg.innerHTML=esc(d.hinweis||"")+(d.meta&&d.meta.kosten_usd!=null?(' <span style="color:var(--k-a89f8f)">· ~$'+d.meta.kosten_usd+'</span>'):''); }
  }catch(e){ if(msg){ msg.style.color="var(--k-dc2626)"; msg.textContent="Ging nicht: "+(e&&e.message?e.message:e); } }
  finally{ if(btn){ btn.disabled=false; btn.textContent="Vorschläge holen"; } }
}
function rezVorschlagRender(d){
  var list=document.getElementById("rezVorList"); if(!list) return;
  var vs=d.vorschlaege||[];
  list.innerHTML=vs.map(function(v,i){
    var ef=v.ernaehrungsform?('<span style="font-size:11px;color:var(--muted)"> · '+esc(v.ernaehrungsform)+'</span>'):'';
    var kc=(v.kcal_geschaetzt!=null)?('~'+Math.round(v.kcal_geschaetzt)+' kcal/Portion'):'kcal unklar';
    var passt=(v.passt_zu_kcal===false)?'<span style="font-size:11px;color:var(--k-b45309)"> · passt nicht ganz zum Bedarf</span>':'';
    var zl=(Array.isArray(v.zutaten)?v.zutaten:[]).map(function(z){ return esc((z.menge?(z.menge+' '):'')+(z.name||''))+(z.aus_vorrat===false?' <span style="color:var(--k-b45309)">(dazu)</span>':''); }).join(' · ');
    return '<div style="border:1px solid var(--line);border-radius:12px;padding:12px 13px;margin-top:10px;background:var(--bg)">'
      +'<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px"><div style="font-weight:700;font-size:14.5px">'+esc(v.name||('Vorschlag '+(i+1)))+ef+'</div><div style="font-size:11.5px;color:var(--muted);white-space:nowrap">⏱ '+(v.zeit_min!=null?(v.zeit_min+' min'):'–')+'</div></div>'
      +(v.kurz?('<div style="font-size:12.5px;color:var(--ink);margin-top:2px">'+esc(v.kurz)+'</div>'):'')
      +'<div style="font-size:12px;color:var(--muted);margin-top:5px"><b style="color:var(--greendk,var(--k-166534))">'+kc+'</b>'+passt+'</div>'
      +'<div style="font-size:12px;color:var(--muted);margin-top:5px;line-height:1.5">'+zl+'</div>'
      +'<button onclick="rezVorschlagUebernehmen('+i+')" style="margin-top:10px;padding:8px 13px;border:0;border-radius:9px;background:var(--green);color:var(--auf-gruen);font-weight:700;font-size:13px;cursor:pointer">Als Rezept übernehmen ▸</button>'
    +'</div>';
  }).join("");
}
async function rezVorschlagUebernehmen(i){
  var v=(window._rezVorschlaege||[])[i]; if(!v) return;
  rezVorschlagClose();
  try{ await openRezeptForm(); }catch(e){}
  /* Jede Zutat SERVERSEITIG zuordnen (cb_zutat_zuordnen: Singular/Plural, Klammern, generisch
     bevorzugt) – dasselbe Gehirn wie der Foto-Weg. Erst dann füllen, damit die „X von Y erkannt"-
     Zeile stimmt und der richtige Katalog-Eintrag drinsteht (Ralph 23.07.: „Eier → Ei"). */
  var zut=(Array.isArray(v.zutaten)?v.zutaten:[]).map(function(z){ return {name:z.name, menge:z.menge, menge_g:z.menge_g, produkt_id:null, treffer:null}; });
  var zug=0;
  await Promise.all(zut.map(async function(z){
    if(!z.name) return;
    try{
      var r=await client.rpc("cb_zutat_zuordnen",{p_name:z.name});
      var t=r&&r.data; if(Array.isArray(t)) t=t[0];
      if(t&&t.gefunden){ z.produkt_id=t.produkt_id; z.treffer={name:t.name, marke:t.marke, score:t.score, art:t.art}; zug++; }
      else { z.treffer={grund:(t&&t.grund)||"nicht im Katalog"}; }
    }catch(e){}
  }));
  var d={ vorschlag:{ name:v.name, portionen:v.portionen, zeit_min:v.zeit_min, zubereitung:v.zubereitung,
    ernaehrungsform:v.ernaehrungsform, naehrwerte_portion:{ kcal:v.kcal_geschaetzt }, zutaten:zut },
    warnungen:['Die kcal-Angabe ist eine Schätzung – danach den Knopf „Nährwerte aus Zutaten berechnen“ drücken für die echten Werte.'
      +(zug<zut.length?' Nicht zugeordnete Zutaten bleiben freie Zutat (kannst du von Hand verknüpfen).':'')],
    zutaten_gesamt:zut.length, zugeordnet:zug };
  try{ rezeptFormFuellen(d); }catch(e){}
}
if(typeof window!=='undefined'){ window.rezVorschlagOpen=rezVorschlagOpen; window.rezVorschlagClose=rezVorschlagClose; window.rezVorschlagRun=rezVorschlagRun; window.rezVorschlagUebernehmen=rezVorschlagUebernehmen; }
function calcMakros(){
  const msg=document.getElementById("rzfCalcMsg");
  let k=0,p=0,kh=0,f=0,linked=0,total=0;
  document.querySelectorAll("#rzfZutaten .rzZ").forEach(row=>{
    const pid=row.querySelector(".rzZpid").value;
    const nm=pid||(row.querySelector(".rzZName").value||"").trim();
    const amt=parseFloat(row.querySelector(".rzZg").value)||0;
    const unit=(row.querySelector(".rzZu")||{}).value||"g";
    if(nm) total++;
    const g=rzToGrams(amt,unit,pid)||0;
    if(pid&&g>0){ const pr=(ALL||[]).find(x=>x.id===pid);
      if(pr){ linked++; const fac=g/100;
        k+=(num(pr.m_kcal)||0)*fac; p+=(num(pr.m_protein)||0)*fac; kh+=(num(pr.m_kh)||0)*fac; f+=(num(pr.m_fett)||0)*fac; } }
  });
  if(!linked){ if(msg){msg.style.color="var(--k-b45309)";msg.textContent="Keine verknüpften Zutaten mit Menge – Katalog-Zutat wählen und Menge in g/ml (bei Stück Portionsgewicht nötig) angeben.";} return; }
  const port=parseFloat(document.getElementById("rzfPort").value)||1;
  const r1=x=>Math.round(x/port), r2=x=>Math.round(x/port*10)/10;
  document.getElementById("rzfKcal").value=r1(k);
  document.getElementById("rzfP").value=r2(p);
  document.getElementById("rzfKh").value=r2(kh);
  document.getElementById("rzfF").value=r2(f);
  if(msg){ msg.style.color="var(--k-16a34a)";
    msg.textContent=`✓ aus ${linked}/${total} Zutaten berechnet`+(linked<total?" (freie Zutaten ohne Nährwerte ignoriert)":""); }
}
async function meldeRezept(id){
  const g=prompt("Was stimmt nicht mit diesem Rezept? (optional)"); if(g===null) return;
  const {error}=await client.rpc("cb_rezept_melden",{p_rezept:id,p_grund:g||""});
  alert(error?("Fehler: "+error.message):"Danke – das Rezept wurde gemeldet und wird geprüft.");
}
