/* Intro-Overlay: gecodete Animation, nur einmal pro Sitzung (Kaltstart), ueberspringbar */
function riHideIntro(){ var o=document.getElementById('introOverlay'); if(!o) return; o.classList.add('hide'); setTimeout(function(){ if(o&&o.parentNode) o.style.display='none'; },600); }
/* ===========================================================================
   DIE VERWANDLUNG

   Das Y (drei Arme, gruen) dreht sich EINMAL ganz herum. Waehrend der Drehung
   wandern die drei Arme auf ihre Plaetze, ein vierter waechst aus der Mitte,
   und die Farben trennen sich: Zutaten gruen, Zusatzstoffe blau, Verarbeitung
   lila, Naehrwert orange.

   Der Kern ist von Anfang an das, was er am Ende ist - ein dunkles Fenster mit
   Ring. Er waechst nur mit, statt sich zu verwandeln.

   Am Ende zaehlt die Skala 0 -> 100. KEINE Beispielzahl: eine "72" waere im
   ersten Moment der App eine erfundene Zahl. Die Skala zeigt den WERTEBEREICH.

   Genau 360 Grad - nicht 405. Sonst landen die Arme schraeg statt in den Ecken,
   und das Ende sieht anders aus als die Startseite.
   =========================================================================== */
function riIntroLauf(){
  var CX=150, CY=100;
  var YARM=[-90, 150, 30];                       // Y: oben, unten-links, unten-rechts
  var SARM=[                                     // Schaltplan: die vier Ecken
    {ax:-124, ay:-66, kx:-76, ky:-66, ex:-38, ey:-24, col:[61,219,122]},
    {ax: 124, ay:-66, kx: 76, ky:-66, ex: 38, ey:-24, col:[90,182,255]},
    {ax:-124, ay: 66, kx:-76, ky: 66, ex:-38, ey: 24, col:[183,155,255]},
    {ax: 124, ay: 66, kx: 76, ky: 66, ex: 38, ey: 24, col:[255,194,75]}
  ];
  var GRUEN=[94,242,160];
  function li(a,b,t){ return a+(b-a)*t; }
  function co(a,b,t){ return 'rgb('+Math.round(li(a[0],b[0],t))+','+Math.round(li(a[1],b[1],t))+','+Math.round(li(a[2],b[2],t))+')'; }

  var rot=document.getElementById('ifRot'), kern=document.getElementById('ifKern');
  var zahl=document.getElementById('ifZahl'), wort=document.getElementById('introWort');
  var claim=document.querySelector('#introOverlay .introClaim');
  if(!rot) return;

  /* Die Pfade stehen im HTML auf d="" - ohne einen ersten Zeichenlauf ist das
     Bild LEER. Genau das sah man in der Startverzoegerung: ein nackter Ring.
     > Ein Startbild, das erst der zweite Frame malt, ist kein Startbild.
     Deshalb: erst das Y zeichnen (me=0), dann die Uhr starten. */
  function zeichne(me){
    for(var i=0;i<4;i++){
      var p=document.getElementById('ifP'+(i+1)), c=document.getElementById('ifK'+(i+1)), z=SARM[i];
      var sx, sy;
      if(i<3){ var r=YARM[i]*Math.PI/180; sx=Math.cos(r)*54; sy=Math.sin(r)*54; }
      else { sx=0; sy=0; p.setAttribute('opacity', me.toFixed(2)); c.setAttribute('opacity', me.toFixed(2)); }
      var ax=li(sx,z.ax,me),      ay=li(sy,z.ay,me);
      var kx=li(sx*0.62,z.kx,me), ky=li(sy*0.62,z.ky,me);
      var ex=li(sx*0.30,z.ex,me), ey=li(sy*0.30,z.ey,me);
      p.setAttribute('d','M'+(CX+ax)+' '+(CY+ay)+' L'+(CX+kx)+' '+(CY+ky)+' L'+(CX+ex)+' '+(CY+ey));
      p.setAttribute('stroke', co(GRUEN, z.col, me));
      c.setAttribute('cx', CX+ax); c.setAttribute('cy', CY+ay);
      c.setAttribute('fill', co(GRUEN, z.col, me));
    }
    kern.setAttribute('r', li(10, 34, me));
  }
  zeichne(0);                                    // das Y steht, bevor irgendetwas laeuft

  var D=2500, t0=performance.now()+600;          // 0,6 s Ruhe: erst sieht man das Y
  function frame(now){
    if(now<t0){ requestAnimationFrame(frame); return; }
    var t=Math.min(1,(now-t0)/D);
    var e = t<.5 ? 4*t*t*t : 1-Math.pow(-2*t+2,3)/2;
    rot.style.transform='rotate('+(e*360)+'deg)';

    var m=Math.max(0,Math.min(1,(t-0.20)/0.60));
    zeichne(m<.5 ? 2*m*m : 1-Math.pow(-2*m+2,2)/2);

    if(t>=1){
      /* Erst jetzt die Skala - sie waechst aus dem Nichts und zaehlt 0 -> 100. */
      zahl.setAttribute('opacity','1');
      var z0=performance.now();
      (function zaehl(n){
        var s=Math.min(1,(n-z0)/1000), se=1-Math.pow(1-s,3);
        zahl.textContent=Math.round(se*100);
        zahl.setAttribute('font-size', (16+se*18).toFixed(1));
        if(s<1) requestAnimationFrame(zaehl);
      })(z0);
      if(wort)  wort.animate([{opacity:0,transform:'translateY(6px)'},{opacity:1,transform:'none'}],{duration:600,delay:500,easing:'cubic-bezier(.22,1,.36,1)',fill:'forwards'});
      return;
    }
    requestAnimationFrame(frame);
  }
  requestAnimationFrame(frame);
}
/* Bei abgeschalteter Bewegung: sofort der Endzustand. Kein Ruckeln, aber auch
   kein leerer Bildschirm - man sieht, worum es geht. */
function riIntroSofort(){
  var rot=document.getElementById('ifRot'), kern=document.getElementById('ifKern');
  var zahl=document.getElementById('ifZahl'), wort=document.getElementById('introWort');
  var claim=document.querySelector('#introOverlay .introClaim');
  if(!rot) return;
  var CX=150, CY=100;
  var S=[{ax:-124,ay:-66,kx:-76,ky:-66,ex:-38,ey:-24,c:'#3DDB7A'},
         {ax: 124,ay:-66,kx: 76,ky:-66,ex: 38,ey:-24,c:'#5AB6FF'},
         {ax:-124,ay: 66,kx:-76,ky: 66,ex:-38,ey: 24,c:'#B79BFF'},
         {ax: 124,ay: 66,kx: 76,ky: 66,ex: 38,ey: 24,c:'#FFC24B'}];
  S.forEach(function(z,i){
    var p=document.getElementById('ifP'+(i+1)), c=document.getElementById('ifK'+(i+1));
    p.setAttribute('d','M'+(CX+z.ax)+' '+(CY+z.ay)+' L'+(CX+z.kx)+' '+(CY+z.ky)+' L'+(CX+z.ex)+' '+(CY+z.ey));
    p.setAttribute('stroke',z.c); p.setAttribute('opacity','1');
    c.setAttribute('cx',CX+z.ax); c.setAttribute('cy',CY+z.ay); c.setAttribute('fill',z.c); c.setAttribute('opacity','1');
  });
  kern.setAttribute('r','34');
  zahl.textContent='100'; zahl.setAttribute('opacity','1');
  if(wort)  wort.style.opacity='1';
  if(claim) claim.style.opacity='1';
}
(function(){
  var o=document.getElementById('introOverlay'); if(!o) return;
  /* Einmal pro SITZUNG: beim Kaltstart der App laeuft es, beim Blaettern in der
     App nicht. Vorher stand hier localStorage - dann sah man es genau einmal im
     Leben des Geraets und nie wieder. Der Ueberspringen-Knopf ist der Notausgang. */
  var reduce=false;
  try{ reduce=window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches; }catch(e){}
  var seen=false;
  try{ seen=sessionStorage.getItem('ri_intro_v3')==='1'; }catch(e){}
  if(seen){ return; }   /* Overlay ist per CSS ohnehin versteckt - kein Blitz, nichts zu tun. */
  try{ sessionStorage.setItem('ri_intro_v3','1'); }catch(e){}
  o.classList.add('introOn');   /* JETZT erst einblenden - nur wenn es wirklich laeuft. */
  if(reduce){ riIntroSofort(); setTimeout(riHideIntro, 1600); return; }
  riIntroLauf();
  setTimeout(riHideIntro, 5500);   /* 0,6 Ruhe + 2,5 Verwandlung + 1,0 Zaehlen + 0,5 stehen */
})();
load();
if(!ADMIN_MODE) setMode('start');
/* Hero bleibt schmal & statisch – kein Schrumpfen beim Scrollen (Intro folgt separat) */
if('serviceWorker' in navigator){ window.addEventListener('load',()=>{ navigator.serviceWorker.register('sw.js').catch(()=>{}); }); }
window.addEventListener('scroll',function(){ if(typeof updateFloatBtns==='function') updateFloatBtns(); },{passive:true});

/* ============================================================
   UPDATE-HINWEIS  (2026-07-13)
   Problem, das uns eingeholt hat: Wer die App offen hat (besonders als
   installierte PWA), führt weiter den ALTEN Code aus – auch nach einem Deploy.
   Ralph hat ein Etikett fotografiert und bekam keine Bewertung, weil sein
   Browser noch den Build von gestern lief. Das trifft JEDEN Nutzer bei JEDEM Deploy.
   Also: Die App prüft selbst, ob sie veraltet ist, und sagt es.
   ============================================================ */
const APP_BUILD = "2026-07-24v";
let _updateGezeigt = false;

/* Riki-Modell für die LESE-Funktionen (Etikett lesen, Herstellerseite recherchieren,
   Zutatenliste zerlegen). Haiku war beim mehrteiligen Supplement-Etikett zu schwach;
   Sonnet liest solche Etiketten zuverlässig. Die Edge-Functions akzeptieren body.modell
   und haben claude-sonnet-4-6 im Preis-Stamm — daher reine Frontend-Umstellung, kein
   Edge-Redeploy. Opus wäre ~5× teurer bei kaum besserer Etikett-Erkennung. */
const RIKI_LESE_MODELL = "claude-sonnet-4-6";

/* Feature-Flags laden: beim Start und immer, wenn sich die Anmeldung ändert. */
ladeFeatures();
try{ client.auth.onAuthStateChange(function(){ ladeFeatures(); }); }catch(e){}

async function pruefeUpdate(){
  if(_updateGezeigt) return;
  try{
    const t = await fetch('index.html?b='+Date.now(), {cache:'no-store'}).then(r=>r.text());
    /* 2026-07-18: Frueher wurde gegen den HTML-Kommentar <!-- build ... --> geprueft.
       Damit stand die Build-Nummer an ZWEI Stellen - und beim Deploy von 18a wurde nur
       eine hochgezaehlt. Folge: Die Seite meldete sich selbst als veraltet, endlos,
       auch direkt nach dem Neuladen. Jetzt wird gegen dieselbe Konstante geprueft,
       die die App auch anzeigt. Eine Zahl, eine Quelle. Der Kommentar in Zeile 2
       bleibt reine Dokumentation und kann nichts mehr kaputtmachen. */
    const m = t.match(/APP_BUILD\s*=\s*"([^"]+)"/);
    if(!m) return;
    if(m[1] !== APP_BUILD) zeigeUpdateBanner();
  }catch(e){ /* offline – kein Problem, dann eben später */ }
}

function zeigeUpdateBanner(){
  if(_updateGezeigt || document.getElementById("updBar")) return;
  _updateGezeigt = true;
  const b=document.createElement("div");
  b.id="updBar";
  b.style.cssText="position:fixed;left:0;right:0;bottom:0;z-index:9995;padding:12px 14px;"
    +"padding-bottom:calc(12px + env(safe-area-inset-bottom));background:var(--k-1d3c24);color:var(--k-ffffff);"
    +"display:flex;align-items:center;gap:10px;box-shadow:0 -4px 18px rgba(0,0,0,.22);font-size:13.5px";
  b.innerHTML='<div style="flex:1;line-height:1.4">Es gibt eine neuere Version von Root Index.<br>'
    +'<span style="opacity:.75;font-size:12px">Ohne Neuladen arbeitest du mit dem alten Stand.</span></div>'
    +'<button onclick="hartNeuLaden()" style="flex:0 0 auto;padding:9px 14px;border:0;border-radius:9px;'
    +'background:var(--k-a8d5a2);color:var(--k-1d3c24);font-weight:700;cursor:pointer;font-size:13.5px">Neu laden</button>';
  document.body.appendChild(b);
}

/* Hart neu laden: Service-Worker-Cache leeren, sonst hält er die alte Hülle fest. */
async function hartNeuLaden(){
  try{
    if('caches' in window){
      const ks = await caches.keys();
      await Promise.all(ks.map(k=>caches.delete(k)));
    }
    if('serviceWorker' in navigator){
      const rs = await navigator.serviceWorker.getRegistrations();
      await Promise.all(rs.map(r=>r.unregister()));
    }
  }catch(e){}
  location.reload(true);
}

/* Manueller „Neu laden"-Knopf im Admin (Ralph 24.07.2026): Nach dem GitHub-Upload dauert es
   ~1 Min, bis GitHub Pages die neue Version gebaut hat – DAS ist serverseitig und kann kein
   Knopf abkürzen. Was der Knopf tut: Er fragt frisch bei GitHub nach der Live-Build-Nummer.
   Ist online schon eine NEUERE da → sofort hart neu laden (Cache + Service-Worker leeren, §5).
   Ist online noch dieselbe → kurze Rückmeldung „GitHub baut noch", KEIN sinnloses Neuladen. */
async function adminNeuLaden(btn){
  var old = btn ? btn.innerHTML : '';
  if(btn){ btn.disabled=true; btn.style.opacity='.6'; btn.innerHTML='⏳ prüfe…'; }
  try{
    var t = await fetch('index.html?b='+Date.now(), {cache:'no-store'}).then(function(r){ return r.text(); });
    var m = t.match(/APP_BUILD\s*=\s*"([^"]+)"/);
    var live = m ? m[1] : null;
    if(live && live !== APP_BUILD){ hartNeuLaden(); return; }   /* GitHub hat eine neuere Version → hart neu laden */
    if(btn){ btn.innerHTML='✓ GitHub baut noch'; setTimeout(function(){ btn.disabled=false; btn.style.opacity=''; btn.innerHTML=old; }, 2600); }
  }catch(e){ hartNeuLaden(); }   /* Abruf fehlgeschlagen → sicherheitshalber hart neu laden */
}
/* Beim Start prüfen, dann alle 5 Minuten, und immer wenn die App
   wieder in den Vordergrund kommt (der PWA-Fall). */
setTimeout(pruefeUpdate, 2500);
setInterval(pruefeUpdate, 5*60*1000);
document.addEventListener("visibilitychange", function(){
  if(document.visibilityState === "visible") pruefeUpdate();
});
